    // ==================== Presets ====================

    private void refreshPresetCombo() {
        presetCombo.removeAllItems();
        if (!PRESETS_DIR.isDirectory()) return;
        File[] files = PRESETS_DIR.listFiles((d, n) -> n.endsWith(".preset"));
        if (files == null) return;
        Arrays.sort(files, Comparator.comparing(File::getName, String.CASE_INSENSITIVE_ORDER));
        for (File f : files) {
            presetCombo.addItem(f.getName().replace(".preset", ""));
        }
    }

    private void savePreset() {
        SlideRow source = null;
        for (SlideRow row : slideRows) {
            if (!row.isTitleGridSlide) { source = row; break; }
        }
        if (source == null) {
            JOptionPane.showMessageDialog(this, "No slide available to save settings from.", "Save Preset", JOptionPane.WARNING_MESSAGE);
            return;
        }

        String name = JOptionPane.showInputDialog(this, "Enter preset name:", "Save Preset", JOptionPane.PLAIN_MESSAGE);
        if (name == null || name.trim().isEmpty()) return;
        name = name.trim().replaceAll("[^a-zA-Z0-9 _\\-]", "");
        if (name.isEmpty()) return;

        PRESETS_DIR.mkdirs();
        Properties props = new Properties();

        // Text formatting
        props.setProperty("fontName", source.getSelectedFont());
        props.setProperty("fontSize", String.valueOf(source.getFontSize()));
        props.setProperty("fontStyle", String.valueOf(source.getFontStyle()));
        props.setProperty("fontColor", colorToHex(source.getFontColor()));
        props.setProperty("alignment", String.valueOf(source.getTextAlignment()));
        props.setProperty("showPin", String.valueOf(source.isShowPin()));
        props.setProperty("textJustify", String.valueOf(source.isTextJustify()));
        props.setProperty("textWidthPct", String.valueOf(source.getTextWidthPct()));
        props.setProperty("textShiftX", String.valueOf(source.getTextShiftX()));
        props.setProperty("highlightText", source.getHighlightText());
        props.setProperty("highlightColor", colorToHex(source.getHighlightColor()));

        // Display
        props.setProperty("displayMode", source.getDisplayMode());
        props.setProperty("subtitleY", String.valueOf(source.getSubtitleY()));
        props.setProperty("subtitleBgOpacity", String.valueOf(source.getSubtitleBgOpacity()));
        props.setProperty("sourceVideoVolume", String.valueOf(source.getSourceVideoVolume()));
        props.setProperty("bgTransparency", String.valueOf(source.getBgTransparency()));

        // Slide number
        props.setProperty("showSlideNumber", String.valueOf(source.isShowSlideNumber()));
        props.setProperty("slideNumberFontName", source.getSlideNumberFontName());
        props.setProperty("slideNumberX", String.valueOf(source.getSlideNumberX()));
        props.setProperty("slideNumberY", String.valueOf(source.getSlideNumberY()));
        props.setProperty("slideNumberSize", String.valueOf(source.getSlideNumberSize()));
        props.setProperty("slideNumberColor", colorToHex(source.getSlideNumberColor()));
        props.setProperty("slideNumberStyle", source.getSlideNumberStyle());
        props.setProperty("slideNumberEffect", source.getSlideNumberEffect());

        // Effects
        props.setProperty("fxRoundCorners", String.valueOf(source.isFxRoundCorners()));
        props.setProperty("fxCornerRadius", String.valueOf(source.getFxCornerRadius()));
        props.setProperty("fxVignetteOn", String.valueOf(source.fxVignetteCheck.isSelected()));
        props.setProperty("fxVignetteVal", String.valueOf(source.getFxVignetteRaw()));
        props.setProperty("fxSepiaOn", String.valueOf(source.fxSepiaCheck.isSelected()));
        props.setProperty("fxSepiaVal", String.valueOf(source.getFxSepiaRaw()));
        props.setProperty("fxGrainOn", String.valueOf(source.fxGrainCheck.isSelected()));
        props.setProperty("fxGrainVal", String.valueOf(source.getFxGrainRaw()));
        props.setProperty("fxWaterRippleOn", String.valueOf(source.fxWaterRippleCheck.isSelected()));
        props.setProperty("fxWaterRippleVal", String.valueOf(source.getFxWaterRippleRaw()));
        props.setProperty("fxGlitchOn", String.valueOf(source.fxGlitchCheck.isSelected()));
        props.setProperty("fxGlitchVal", String.valueOf(source.getFxGlitchRaw()));
        props.setProperty("fxShakeOn", String.valueOf(source.fxShakeCheck.isSelected()));
        props.setProperty("fxShakeVal", String.valueOf(source.getFxShakeRaw()));
        props.setProperty("fxScanlineOn", String.valueOf(source.fxScanlineCheck.isSelected()));
        props.setProperty("fxScanlineVal", String.valueOf(source.getFxScanlineRaw()));
        props.setProperty("fxRaisedOn", String.valueOf(source.fxRaisedCheck.isSelected()));
        props.setProperty("fxRaisedVal", String.valueOf(source.getFxRaisedRaw()));
        props.setProperty("fxOtherKind", source.getFxOtherKind());
        props.setProperty("fxOtherVal", String.valueOf(source.getFxOtherRaw()));

        // Overlay
        props.setProperty("overlayEnabled", String.valueOf(source.isOverlayEnabled()));
        props.setProperty("overlayShape", source.getOverlayShape());
        props.setProperty("overlayBgMode", source.getOverlayBgMode());
        props.setProperty("overlayBgColor", colorToHex(source.getOverlayBgColor()));
        props.setProperty("overlayX", String.valueOf(source.getOverlayX()));
        props.setProperty("overlayY", String.valueOf(source.getOverlayY()));
        props.setProperty("overlaySize", String.valueOf(source.getOverlaySize()));

        // Slide text layers
        List<SlideTextData> texts = source.getSlideTextFormats();
        props.setProperty("slideTextCount", String.valueOf(texts.size()));
        for (int i = 0; i < texts.size(); i++) {
            SlideTextData t = texts.get(i);
            String p = "slideText." + i + ".";
            props.setProperty(p + "show", String.valueOf(t.show));
            props.setProperty(p + "fontName", t.fontName);
            props.setProperty(p + "fontSize", String.valueOf(t.fontSize));
            props.setProperty(p + "fontStyle", String.valueOf(t.fontStyle));
            props.setProperty(p + "color", colorToHex(t.color));
            props.setProperty(p + "x", String.valueOf(t.x));
            props.setProperty(p + "y", String.valueOf(t.y));
            props.setProperty(p + "bgOpacity", String.valueOf(t.bgOpacity));
            props.setProperty(p + "bgColor", colorToHex(t.bgColor));
            props.setProperty(p + "bgPaddingPct", String.valueOf(t.bgPaddingPct));
            props.setProperty(p + "bgRoundPct", String.valueOf(t.bgRoundPct));
            props.setProperty(p + "bgColor2", colorToHex(t.bgColor2 != null ? t.bgColor2 : new Color(60, 60, 60)));
            props.setProperty(p + "bgFillKind", t.bgFillKind != null ? t.bgFillKind : "Solid");
            props.setProperty(p + "bgFillAngle", String.valueOf(t.bgFillAngle));
            props.setProperty(p + "bgFillSpacing", String.valueOf(t.bgFillSpacing));
            props.setProperty(p + "bgNoiseKind", t.bgNoiseKind != null ? t.bgNoiseKind : "None");
            props.setProperty(p + "bgNoiseIntensity", String.valueOf(t.bgNoiseIntensity));
            props.setProperty(p + "bgFrostedBlur", String.valueOf(t.bgFrostedBlur));
            props.setProperty(p + "bgShape", t.bgShape != null ? t.bgShape : "Rounded");
            props.setProperty(p + "bgCornerTL", String.valueOf(t.bgCornerTL));
            props.setProperty(p + "bgCornerTR", String.valueOf(t.bgCornerTR));
            props.setProperty(p + "bgCornerBL", String.valueOf(t.bgCornerBL));
            props.setProperty(p + "bgCornerBR", String.valueOf(t.bgCornerBR));
            props.setProperty(p + "bgBorderStyle", t.bgBorderStyle != null ? t.bgBorderStyle : "None");
            props.setProperty(p + "bgBorderWidth", String.valueOf(t.bgBorderWidth));
            props.setProperty(p + "bgBorderColor", colorToHex(t.bgBorderColor != null ? t.bgBorderColor : Color.WHITE));
            props.setProperty(p + "bgShadow", String.valueOf(t.bgShadow));
            props.setProperty(p + "bgShadowDx", String.valueOf(t.bgShadowDx));
            props.setProperty(p + "bgShadowDy", String.valueOf(t.bgShadowDy));
            props.setProperty(p + "bgShadowBlur", String.valueOf(t.bgShadowBlur));
            props.setProperty(p + "bgInnerShadow", String.valueOf(t.bgInnerShadow));
            props.setProperty(p + "bgInnerShadowSize", String.valueOf(t.bgInnerShadowSize));
            props.setProperty(p + "bgOuterGlow", String.valueOf(t.bgOuterGlow));
            props.setProperty(p + "bgOuterGlowSize", String.valueOf(t.bgOuterGlowSize));
            props.setProperty(p + "bgOuterGlowColor", colorToHex(t.bgOuterGlowColor != null ? t.bgOuterGlowColor : new Color(255, 220, 120)));
            props.setProperty(p + "justify", String.valueOf(t.justify));
            props.setProperty(p + "widthPct", String.valueOf(t.widthPct));
            props.setProperty(p + "shiftX", String.valueOf(t.shiftX));
            props.setProperty(p + "alignment", String.valueOf(t.alignment));
            props.setProperty(p + "textEffect", t.textEffect);
            props.setProperty(p + "textEffectIntensity", String.valueOf(t.textEffectIntensity));
            props.setProperty(p + "highlightText", t.highlightText);
            props.setProperty(p + "highlightColor", colorToHex(t.highlightColor));
            props.setProperty(p + "highlightStyle", t.highlightStyle);
            props.setProperty(p + "highlightTightness", String.valueOf(t.highlightTightness));
            props.setProperty(p + "underlineStyle", t.underlineStyle);
            props.setProperty(p + "underlineText", t.underlineText);
            props.setProperty(p + "boldText", t.boldText);
            props.setProperty(p + "italicText", t.italicText);
            props.setProperty(p + "colorText", t.colorText);
            props.setProperty(p + "colorTextColor", colorToHex(t.colorTextColor));
            props.setProperty(p + "animEnabled", String.valueOf(t.animEnabled));
            props.setProperty(p + "animPath", t.animPath);
            props.setProperty(p + "animDurationMs", String.valueOf(t.animDurationMs));
            props.setProperty(p + "animStartMs", String.valueOf(t.animStartMs));
            props.setProperty(p + "animEasing", t.animEasing);
            props.setProperty(p + "tiltDegrees", String.valueOf(t.tiltDegrees));
            props.setProperty(p + "letterSpacing", String.valueOf(t.letterSpacing));
            props.setProperty(p + "lineSpacing", String.valueOf(t.lineSpacing));
            props.setProperty(p + "opacity", String.valueOf(t.opacity));
        }

        // Per-text audio highlight settings (FX, HL color, glow size).
        // Stored parallel to the slideText.<i>.* block above; index aligns with
        // text-row index. First slide is the master, so these get broadcast to
        // every slide on Load Preset via applyFormatting.
        java.util.List<String>  audioHlEffectsList = source.getAudioHlEffectsList();
        java.util.List<Color>   audioHlColorList   = source.getAudioHlColorList();
        java.util.List<Integer> audioGlowSizeList  = source.getAudioGlowSizeList();
        java.util.List<String>  karaokeStyleList   = source.getSlideAudioKaraokeStyleList();
        java.util.List<Color>   karaokeColorList   = source.getSlideAudioKaraokeColorList();
        for (int i = 0; i < texts.size(); i++) {
            String p = "slideText." + i + ".";
            String  fx    = i < audioHlEffectsList.size() ? audioHlEffectsList.get(i) : DEFAULT_AUDIO_HL_EFFECTS;
            Color   color = i < audioHlColorList.size()   ? audioHlColorList.get(i)   : DEFAULT_AUDIO_HL_COLOR;
            Integer glow  = i < audioGlowSizeList.size()  ? audioGlowSizeList.get(i)  : DEFAULT_AUDIO_GLOW_SIZE;
            props.setProperty(p + "audioHlEffects", fx != null ? fx : DEFAULT_AUDIO_HL_EFFECTS);
            props.setProperty(p + "audioHlColor",   colorToHex(color != null ? color : DEFAULT_AUDIO_HL_COLOR));
            props.setProperty(p + "audioGlowSize",  String.valueOf(glow != null && glow > 0 ? glow : DEFAULT_AUDIO_GLOW_SIZE));
            String kStyle = i < karaokeStyleList.size() ? karaokeStyleList.get(i) : DEFAULT_KARAOKE_STYLE;
            Color  kColor = i < karaokeColorList.size() ? karaokeColorList.get(i) : DEFAULT_KARAOKE_COLOR;
            props.setProperty(p + "karaokeStyle", kStyle != null ? kStyle : DEFAULT_KARAOKE_STYLE);
            props.setProperty(p + "karaokeColor", colorToHex(kColor != null ? kColor : DEFAULT_KARAOKE_COLOR));
        }

        // Orientation
        props.setProperty("orientation", isPortrait() ? "Portrait" : "Landscape");

        // Quiz timer shared/visual settings (per-slide fields like the
        // "enabled" flag, correct option, and question audio file are NOT
        // saved — those belong to the slide, not the preset).
        QuizSlide qs = source.getQuiz();
        if (qs != null) {
            props.setProperty("quiz.timerStyle",         qs.timerStyle);
            props.setProperty("quiz.timerXPct",          String.valueOf(qs.timerXPct));
            props.setProperty("quiz.timerYPct",          String.valueOf(qs.timerYPct));
            props.setProperty("quiz.timerSizePct",       String.valueOf(qs.timerSizePct));
            props.setProperty("quiz.timerWidthPct",      String.valueOf(qs.timerWidthPct));
            props.setProperty("quiz.timerColor",         colorToHex(qs.timerColor != null
                    ? qs.timerColor : new Color(80, 200, 255)));
            props.setProperty("quiz.progressBarShape",   qs.progressBarShape != null
                    ? qs.progressBarShape : "Rounded");
            props.setProperty("quiz.timerTextColor",     colorToHex(qs.timerTextColor != null
                    ? qs.timerTextColor : Color.WHITE));
            props.setProperty("quiz.timerFont",          qs.timerFont != null ? qs.timerFont : "Segoe UI");
            props.setProperty("quiz.timerLabel",         qs.timerLabel != null ? qs.timerLabel : "");
            props.setProperty("quiz.digitXOffsetPct",    String.valueOf(qs.digitXOffsetPct));
            props.setProperty("quiz.digitYOffsetPct",    String.valueOf(qs.digitYOffsetPct));
            props.setProperty("quiz.digitSizePct",       String.valueOf(qs.digitSizePct));
            props.setProperty("quiz.digitBold",          String.valueOf(qs.digitBold));
            props.setProperty("quiz.digitShadow",        String.valueOf(qs.digitShadow));
            props.setProperty("quiz.digitShow",          String.valueOf(qs.digitShow));
            props.setProperty("quiz.barReverse",         String.valueOf(qs.barReverse));
            props.setProperty("quiz.revealMarkStyle",    qs.revealMarkStyle != null ? qs.revealMarkStyle : "Check");
            props.setProperty("quiz.revealMarkSizePct",  String.valueOf(qs.revealMarkSizePct));
            props.setProperty("quiz.revealMarkColor",    colorToHex(qs.revealMarkColor != null
                    ? qs.revealMarkColor : new Color(60, 220, 110)));
            props.setProperty("quiz.revealPadPct",       String.valueOf(qs.revealPadPct));
            props.setProperty("quiz.hideTextIndex",      String.valueOf(qs.hideTextIndex));
            props.setProperty("quiz.hideRevealAnimation",  qs.hideRevealAnimation != null
                    ? qs.hideRevealAnimation : "Fade");
            props.setProperty("quiz.hideRevealDurationMs", String.valueOf(qs.hideRevealDurationMs));
            props.setProperty("quiz.hideRevealEasing",     qs.hideRevealEasing != null
                    ? qs.hideRevealEasing : "Ease Out");
            props.setProperty("quiz.timerSeconds",       String.valueOf(qs.timerSeconds));
            props.setProperty("quiz.redThresholdSeconds", String.valueOf(qs.redThresholdSeconds));
            props.setProperty("quiz.timerStartMode",     qs.timerStartMode != null
                    ? qs.timerStartMode : "AfterQuestion");
            // Animation knobs + custom red/secondary (new fields — older presets
            // omit these and fall back to defaults on load).
            props.setProperty("quiz.timerAnimation",     qs.timerAnimation != null
                    ? qs.timerAnimation : "Pulse");
            props.setProperty("quiz.timerAnimStrengthPct",
                    String.valueOf(qs.timerAnimStrengthPct));
            props.setProperty("quiz.timerAnimTrigger",   qs.timerAnimTrigger != null
                    ? qs.timerAnimTrigger : "Red Phase");
            props.setProperty("quiz.timerAnimEasing",    qs.timerAnimEasing != null
                    ? qs.timerAnimEasing : "Ease Out");
            if (qs.timerRedColor != null)
                props.setProperty("quiz.timerRedColor", colorToHex(qs.timerRedColor));
            props.setProperty("quiz.tickPreset",         qs.tickPreset != null ? qs.tickPreset : "Stock: Classic Clock");
            props.setProperty("quiz.dingPreset",         qs.dingPreset != null ? qs.dingPreset : "Stock: Bell");
            if (qs.customTickFile != null)
                props.setProperty("quiz.customTickFile", qs.customTickFile.getAbsolutePath());
            if (qs.customDingFile != null)
                props.setProperty("quiz.customDingFile", qs.customDingFile.getAbsolutePath());
            // Per-cue VISUALS only — effects / hl color / glow / rank /
            // replay flag, keyed by targetTextIndex. Audio file and start
            // time stay per-slide and are intentionally not persisted in
            // the preset (matches copyVisualSettingsFrom).
            int cueCount = qs.cues != null ? qs.cues.size() : 0;
            props.setProperty("quiz.cueCount", String.valueOf(cueCount));
            for (int ci = 0; ci < cueCount; ci++) {
                QuizSlide.QuizCue c = qs.cues.get(ci);
                if (c == null) continue;
                String cp = "quiz.cue" + ci + ".";
                props.setProperty(cp + "targetTextIndex", String.valueOf(c.targetTextIndex));
                props.setProperty(cp + "effects",         c.effects != null ? c.effects : DEFAULT_AUDIO_HL_EFFECTS);
                props.setProperty(cp + "hlColor",         colorToHex(c.hlColor != null
                        ? c.hlColor : new Color(255, 200, 50, 160)));
                props.setProperty(cp + "glowSize",        String.valueOf(c.glowSize));
                props.setProperty(cp + "rank",            String.valueOf(c.rank));
                props.setProperty(cp + "playAfterReveal", String.valueOf(c.playAfterReveal));
            }
        }

        File file = new File(PRESETS_DIR, name + ".preset");
        try (FileOutputStream fos = new FileOutputStream(file)) {
            props.store(fos, "GifSlideShowApp Preset: " + name);
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this, "Failed to save preset: " + ex.getMessage(), "Error", JOptionPane.ERROR_MESSAGE);
            return;
        }

        refreshPresetCombo();
        presetCombo.setSelectedItem(name);
        JOptionPane.showMessageDialog(this, "Preset \"" + name + "\" saved.", "Save Preset", JOptionPane.INFORMATION_MESSAGE);
    }

    private void loadPreset() {
        String name = (String) presetCombo.getSelectedItem();
        if (name == null || name.isEmpty()) {
            JOptionPane.showMessageDialog(this, "No preset selected.", "Load Preset", JOptionPane.WARNING_MESSAGE);
            return;
        }

        File file = new File(PRESETS_DIR, name + ".preset");
        if (!file.exists()) {
            JOptionPane.showMessageDialog(this, "Preset file not found.", "Load Preset", JOptionPane.ERROR_MESSAGE);
            return;
        }

        Properties props = new Properties();
        try (FileInputStream fis = new FileInputStream(file)) {
            props.load(fis);
        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this, "Failed to load preset: " + ex.getMessage(), "Error", JOptionPane.ERROR_MESSAGE);
            return;
        }

        // Parse values
        String fontName = props.getProperty("fontName", "Segoe UI");
        int fontSize = Integer.parseInt(props.getProperty("fontSize", "28"));
        int fontStyle = Integer.parseInt(props.getProperty("fontStyle", "0"));
        Color fontColor = hexToColor(props.getProperty("fontColor", "#FFFFFF"));
        int alignment = Integer.parseInt(props.getProperty("alignment", String.valueOf(SwingConstants.LEFT)));
        boolean showPin = Boolean.parseBoolean(props.getProperty("showPin", "false"));
        boolean textJustify = Boolean.parseBoolean(props.getProperty("textJustify", "false"));
        int textWidthPct = Integer.parseInt(props.getProperty("textWidthPct", "90"));
        int textShiftX = Integer.parseInt(props.getProperty("textShiftX", "0"));
        String highlightText = props.getProperty("highlightText", "");
        Color highlightColor = hexToColor(props.getProperty("highlightColor", "#FFFF00B4"));

        String displayMode = props.getProperty("displayMode", "Blur-Fit");
        int subtitleY = Integer.parseInt(props.getProperty("subtitleY", "5"));
        int subtitleBgOpacity = Integer.parseInt(props.getProperty("subtitleBgOpacity", "78"));
        int sourceVideoVolume = Integer.parseInt(props.getProperty("sourceVideoVolume", "25"));
        int bgTransparency = Integer.parseInt(props.getProperty("bgTransparency", "0"));

        boolean showSlideNumber = Boolean.parseBoolean(props.getProperty("showSlideNumber", "false"));
        String slideNumberFontName = props.getProperty("slideNumberFontName", loadedFontNames.length > 0 ? loadedFontNames[0] : "Segoe UI");
        int slideNumberX = Integer.parseInt(props.getProperty("slideNumberX", "50"));
        int slideNumberY = Integer.parseInt(props.getProperty("slideNumberY", "50"));
        int slideNumberSize = Integer.parseInt(props.getProperty("slideNumberSize", "80"));
        Color slideNumberColor = hexToColor(props.getProperty("slideNumberColor", "#FFFFFF"));
        String slideNumberStyle = props.getProperty("slideNumberStyle", "Circle");
        String slideNumberEffect = props.getProperty("slideNumberEffect", "None");

        boolean fxRoundCorners = Boolean.parseBoolean(props.getProperty("fxRoundCorners", "false"));
        int fxCornerRadius = Integer.parseInt(props.getProperty("fxCornerRadius", "40"));
        boolean fxVignetteOn = Boolean.parseBoolean(props.getProperty("fxVignetteOn", "false"));
        int fxVignetteVal = Integer.parseInt(props.getProperty("fxVignetteVal", "50"));
        boolean fxSepiaOn = Boolean.parseBoolean(props.getProperty("fxSepiaOn", "false"));
        int fxSepiaVal = Integer.parseInt(props.getProperty("fxSepiaVal", "50"));
        boolean fxGrainOn = Boolean.parseBoolean(props.getProperty("fxGrainOn", "false"));
        int fxGrainVal = Integer.parseInt(props.getProperty("fxGrainVal", "50"));
        boolean fxWaterRippleOn = Boolean.parseBoolean(props.getProperty("fxWaterRippleOn", "false"));
        int fxWaterRippleVal = Integer.parseInt(props.getProperty("fxWaterRippleVal", "50"));
        boolean fxGlitchOn = Boolean.parseBoolean(props.getProperty("fxGlitchOn", "false"));
        int fxGlitchVal = Integer.parseInt(props.getProperty("fxGlitchVal", "50"));
        boolean fxShakeOn = Boolean.parseBoolean(props.getProperty("fxShakeOn", "false"));
        int fxShakeVal = Integer.parseInt(props.getProperty("fxShakeVal", "50"));
        boolean fxScanlineOn = Boolean.parseBoolean(props.getProperty("fxScanlineOn", "false"));
        int fxScanlineVal = Integer.parseInt(props.getProperty("fxScanlineVal", "50"));
        boolean fxRaisedOn = Boolean.parseBoolean(props.getProperty("fxRaisedOn", "false"));
        int fxRaisedVal = Integer.parseInt(props.getProperty("fxRaisedVal", "50"));
        String fxOtherKind = props.getProperty("fxOtherKind", "None");
        int fxOtherVal = Integer.parseInt(props.getProperty("fxOtherVal", "50"));

        String overlayShape = props.getProperty("overlayShape", "Rectangular");
        String overlayBgMode = props.getProperty("overlayBgMode", "Blur");
        Color overlayBgColor = hexToColor(props.getProperty("overlayBgColor", "#152B2B"));
        int overlayX = Integer.parseInt(props.getProperty("overlayX", "50"));
        int overlayY = Integer.parseInt(props.getProperty("overlayY", "50"));
        int overlaySize = Integer.parseInt(props.getProperty("overlaySize", "80"));

        // Slide text layers
        int slideTextCount = Integer.parseInt(props.getProperty("slideTextCount", "1"));
        List<SlideTextData> slideTextFormats = new ArrayList<>();
        for (int i = 0; i < slideTextCount; i++) {
            String p = "slideText." + i + ".";
            SlideTextData loaded = new SlideTextData(
                    Boolean.parseBoolean(props.getProperty(p + "show", "false")),
                    "",  // text content not saved in presets
                    props.getProperty(p + "fontName", loadedFontNames.length > 0 ? loadedFontNames[0] : "Segoe UI"),
                    Integer.parseInt(props.getProperty(p + "fontSize", "40")),
                    Integer.parseInt(props.getProperty(p + "fontStyle", "0")),
                    hexToColor(props.getProperty(p + "color", "#FFFF00")),
                    Integer.parseInt(props.getProperty(p + "x", "50")),
                    Integer.parseInt(props.getProperty(p + "y", "50")),
                    Integer.parseInt(props.getProperty(p + "bgOpacity", "0")),
                    hexToColor(props.getProperty(p + "bgColor", "#000000")),
                    Boolean.parseBoolean(props.getProperty(p + "justify", "false")),
                    Integer.parseInt(props.getProperty(p + "widthPct", "100")),
                    Integer.parseInt(props.getProperty(p + "shiftX", "0")),
                    Integer.parseInt(props.getProperty(p + "alignment", String.valueOf(SwingConstants.CENTER))),
                    props.getProperty(p + "textEffect", "None"),
                    Integer.parseInt(props.getProperty(p + "textEffectIntensity", "50")),
                    props.getProperty(p + "highlightText", ""),
                    hexToColor(props.getProperty(p + "highlightColor", "#FF6496B4")),
                    props.getProperty(p + "highlightStyle", "Regular"),
                    Integer.parseInt(props.getProperty(p + "highlightTightness", "50")),
                    props.getProperty(p + "underlineStyle", "None"),
                    props.getProperty(p + "underlineText", ""),
                    props.getProperty(p + "boldText", ""),
                    props.getProperty(p + "italicText", ""),
                    props.getProperty(p + "colorText", ""),
                    hexToColor(props.getProperty(p + "colorTextColor", "#FF5050")),
                    false, false, 50, 3, "Sequential",
                    Boolean.parseBoolean(props.getProperty(p + "animEnabled", "false")),
                    props.getProperty(p + "animPath", "From Left"),
                    Integer.parseInt(props.getProperty(p + "animDurationMs", "1500")),
                    Integer.parseInt(props.getProperty(p + "animStartMs", "0")),
                    props.getProperty(p + "animEasing", "Ease Out"),
                    Integer.parseInt(props.getProperty(p + "tiltDegrees", "0")),
                    Integer.parseInt(props.getProperty(p + "letterSpacing", "0")),
                    Integer.parseInt(props.getProperty(p + "lineSpacing", "0")),
                    Integer.parseInt(props.getProperty(p + "opacity", "100"))
            );
            loaded.bgPaddingPct      = Integer.parseInt(props.getProperty(p + "bgPaddingPct", "50"));
            loaded.bgRoundPct        = Integer.parseInt(props.getProperty(p + "bgRoundPct", "10"));
            loaded.bgColor2          = hexToColor(props.getProperty(p + "bgColor2", "#3C3C3C"));
            // bgFillKind defaults to Solid; legacy bgGradient=true upgrades to Linear.
            String legacyGrad = props.getProperty(p + "bgGradient");
            loaded.bgFillKind        = props.getProperty(p + "bgFillKind",
                    "true".equalsIgnoreCase(legacyGrad) ? "Linear" : "Solid");
            loaded.bgFillAngle       = Integer.parseInt(props.getProperty(p + "bgFillAngle", "90"));
            loaded.bgFillSpacing     = Integer.parseInt(props.getProperty(p + "bgFillSpacing", "12"));
            // Legacy bgGrainy=true upgrades to Grain.
            String legacyGrainy = props.getProperty(p + "bgGrainy");
            loaded.bgNoiseKind       = props.getProperty(p + "bgNoiseKind",
                    "true".equalsIgnoreCase(legacyGrainy) ? "Grain" : "None");
            loaded.bgNoiseIntensity  = Integer.parseInt(props.getProperty(p + "bgNoiseIntensity",
                    props.getProperty(p + "bgGrainyIntensity", "50")));
            loaded.bgFrostedBlur     = Integer.parseInt(props.getProperty(p + "bgFrostedBlur", "0"));
            loaded.bgShape           = props.getProperty(p + "bgShape", "Rounded");
            loaded.bgCornerTL        = Boolean.parseBoolean(props.getProperty(p + "bgCornerTL", "true"));
            loaded.bgCornerTR        = Boolean.parseBoolean(props.getProperty(p + "bgCornerTR", "true"));
            loaded.bgCornerBL        = Boolean.parseBoolean(props.getProperty(p + "bgCornerBL", "true"));
            loaded.bgCornerBR        = Boolean.parseBoolean(props.getProperty(p + "bgCornerBR", "true"));
            loaded.bgBorderStyle     = props.getProperty(p + "bgBorderStyle", "None");
            loaded.bgBorderWidth     = Integer.parseInt(props.getProperty(p + "bgBorderWidth", "2"));
            loaded.bgBorderColor     = hexToColor(props.getProperty(p + "bgBorderColor", "#FFFFFF"));
            loaded.bgShadow          = Boolean.parseBoolean(props.getProperty(p + "bgShadow", "false"));
            loaded.bgShadowDx        = Integer.parseInt(props.getProperty(p + "bgShadowDx", "4"));
            loaded.bgShadowDy        = Integer.parseInt(props.getProperty(p + "bgShadowDy", "4"));
            loaded.bgShadowBlur      = Integer.parseInt(props.getProperty(p + "bgShadowBlur", "8"));
            loaded.bgInnerShadow     = Boolean.parseBoolean(props.getProperty(p + "bgInnerShadow", "false"));
            loaded.bgInnerShadowSize = Integer.parseInt(props.getProperty(p + "bgInnerShadowSize", "6"));
            loaded.bgOuterGlow       = Boolean.parseBoolean(props.getProperty(p + "bgOuterGlow", "false"));
            loaded.bgOuterGlowSize   = Integer.parseInt(props.getProperty(p + "bgOuterGlowSize", "8"));
            loaded.bgOuterGlowColor  = hexToColor(props.getProperty(p + "bgOuterGlowColor", "#FFDC78"));
            slideTextFormats.add(loaded);
        }

        // Per-text audio highlight settings (parallel to slideTextFormats).
        // Older preset files written before this feature won't have these keys —
        // hexToColor / parseInt fall back to the static defaults so older presets
        // still load and behave like the original single-effect "Glow" highlight.
        List<String>  audioHlEffectsList = new ArrayList<>();
        List<Color>   audioHlColorList   = new ArrayList<>();
        List<Integer> audioGlowSizeList  = new ArrayList<>();
        List<String>  karaokeStyleList   = new ArrayList<>();
        List<Color>   karaokeColorList   = new ArrayList<>();
        for (int i = 0; i < slideTextCount; i++) {
            String p = "slideText." + i + ".";
            audioHlEffectsList.add(props.getProperty(p + "audioHlEffects", DEFAULT_AUDIO_HL_EFFECTS));
            audioHlColorList.add(hexToColor(props.getProperty(p + "audioHlColor",
                    colorToHex(DEFAULT_AUDIO_HL_COLOR))));
            audioGlowSizeList.add(Integer.parseInt(
                    props.getProperty(p + "audioGlowSize", String.valueOf(DEFAULT_AUDIO_GLOW_SIZE))));
            karaokeStyleList.add(props.getProperty(p + "karaokeStyle", DEFAULT_KARAOKE_STYLE));
            karaokeColorList.add(hexToColor(props.getProperty(p + "karaokeColor",
                    colorToHex(DEFAULT_KARAOKE_COLOR))));
        }

        // Orientation
        String orientation = props.getProperty("orientation", "Landscape");
        if ("Portrait".equals(orientation)) {
            orientationCombo.setSelectedItem("Portrait (1080×1920)");
        } else {
            orientationCombo.setSelectedItem("Landscape (1920×1080)");
        }

        // Quiz timer shared/visual settings — read from preset (defaults
        // mirror QuizSlide field defaults so older presets still load).
        QuizSlide tmpl = new QuizSlide();
        tmpl.timerStyle         = props.getProperty("quiz.timerStyle", tmpl.timerStyle);
        tmpl.timerXPct          = Integer.parseInt(props.getProperty("quiz.timerXPct",
                String.valueOf(tmpl.timerXPct)));
        tmpl.timerYPct          = Integer.parseInt(props.getProperty("quiz.timerYPct",
                String.valueOf(tmpl.timerYPct)));
        tmpl.timerSizePct       = Integer.parseInt(props.getProperty("quiz.timerSizePct",
                String.valueOf(tmpl.timerSizePct)));
        tmpl.timerWidthPct      = Integer.parseInt(props.getProperty("quiz.timerWidthPct",
                String.valueOf(tmpl.timerWidthPct)));
        tmpl.timerColor         = hexToColor(props.getProperty("quiz.timerColor",
                colorToHex(tmpl.timerColor)));
        tmpl.progressBarShape   = props.getProperty("quiz.progressBarShape",
                tmpl.progressBarShape != null ? tmpl.progressBarShape : "Rounded");
        tmpl.timerTextColor     = hexToColor(props.getProperty("quiz.timerTextColor",
                colorToHex(tmpl.timerTextColor != null ? tmpl.timerTextColor : Color.WHITE)));
        tmpl.timerFont          = props.getProperty("quiz.timerFont",
                tmpl.timerFont != null ? tmpl.timerFont : "Segoe UI");
        tmpl.timerLabel         = props.getProperty("quiz.timerLabel", "");
        tmpl.digitXOffsetPct    = Integer.parseInt(props.getProperty("quiz.digitXOffsetPct",
                String.valueOf(tmpl.digitXOffsetPct)));
        tmpl.digitYOffsetPct    = Integer.parseInt(props.getProperty("quiz.digitYOffsetPct",
                String.valueOf(tmpl.digitYOffsetPct)));
        tmpl.digitSizePct       = Integer.parseInt(props.getProperty("quiz.digitSizePct",
                String.valueOf(tmpl.digitSizePct)));
        tmpl.digitBold          = Boolean.parseBoolean(props.getProperty("quiz.digitBold",
                String.valueOf(tmpl.digitBold)));
        tmpl.digitShadow        = Boolean.parseBoolean(props.getProperty("quiz.digitShadow",
                String.valueOf(tmpl.digitShadow)));
        tmpl.digitShow          = Boolean.parseBoolean(props.getProperty("quiz.digitShow",
                String.valueOf(tmpl.digitShow)));
        tmpl.barReverse         = Boolean.parseBoolean(props.getProperty("quiz.barReverse",
                String.valueOf(tmpl.barReverse)));
        tmpl.revealMarkStyle    = props.getProperty("quiz.revealMarkStyle",
                tmpl.revealMarkStyle != null ? tmpl.revealMarkStyle : "Check");
        tmpl.revealMarkSizePct  = Integer.parseInt(props.getProperty("quiz.revealMarkSizePct",
                String.valueOf(tmpl.revealMarkSizePct)));
        tmpl.revealMarkColor    = hexToColor(props.getProperty("quiz.revealMarkColor",
                colorToHex(tmpl.revealMarkColor != null ? tmpl.revealMarkColor
                        : new Color(60, 220, 110))));
        tmpl.revealPadPct       = Integer.parseInt(props.getProperty("quiz.revealPadPct",
                String.valueOf(tmpl.revealPadPct)));
        tmpl.hideTextIndex      = Integer.parseInt(props.getProperty("quiz.hideTextIndex",
                String.valueOf(tmpl.hideTextIndex)));
        tmpl.hideRevealAnimation  = props.getProperty("quiz.hideRevealAnimation",
                tmpl.hideRevealAnimation);
        tmpl.hideRevealDurationMs = Integer.parseInt(props.getProperty(
                "quiz.hideRevealDurationMs", String.valueOf(tmpl.hideRevealDurationMs)));
        tmpl.hideRevealEasing     = props.getProperty("quiz.hideRevealEasing",
                tmpl.hideRevealEasing);
        tmpl.timerSeconds       = Integer.parseInt(props.getProperty("quiz.timerSeconds",
                String.valueOf(tmpl.timerSeconds)));
        tmpl.redThresholdSeconds = Integer.parseInt(props.getProperty("quiz.redThresholdSeconds",
                String.valueOf(tmpl.redThresholdSeconds)));
        tmpl.timerStartMode     = props.getProperty("quiz.timerStartMode", tmpl.timerStartMode);
        tmpl.timerAnimation       = props.getProperty("quiz.timerAnimation", tmpl.timerAnimation);
        tmpl.timerAnimStrengthPct = Integer.parseInt(props.getProperty(
                "quiz.timerAnimStrengthPct", String.valueOf(tmpl.timerAnimStrengthPct)));
        tmpl.timerAnimTrigger     = props.getProperty("quiz.timerAnimTrigger", tmpl.timerAnimTrigger);
        tmpl.timerAnimEasing      = props.getProperty("quiz.timerAnimEasing", tmpl.timerAnimEasing);
        String redHex  = props.getProperty("quiz.timerRedColor");
        tmpl.timerRedColor       = (redHex != null && !redHex.isEmpty())
                ? hexToColor(redHex) : null;
        tmpl.tickPreset         = props.getProperty("quiz.tickPreset", tmpl.tickPreset);
        tmpl.dingPreset         = props.getProperty("quiz.dingPreset", tmpl.dingPreset);
        String ctp = props.getProperty("quiz.customTickFile");
        if (ctp != null && !ctp.isEmpty()) tmpl.customTickFile = new File(ctp);
        String cdp = props.getProperty("quiz.customDingFile");
        if (cdp != null && !cdp.isEmpty()) tmpl.customDingFile = new File(cdp);
        // Per-cue VISUALS — see save side. copyVisualSettingsFrom merges
        // these into each row's existing cue list by targetTextIndex, so
        // each slide keeps its own audio recording.
        int cueCount = Integer.parseInt(props.getProperty("quiz.cueCount", "0"));
        tmpl.cues = new ArrayList<>();
        for (int ci = 0; ci < cueCount; ci++) {
            String cp = "quiz.cue" + ci + ".";
            if (props.getProperty(cp + "targetTextIndex") == null) continue;
            QuizSlide.QuizCue c = new QuizSlide.QuizCue();
            c.targetTextIndex = Integer.parseInt(props.getProperty(cp + "targetTextIndex", "0"));
            c.effects         = props.getProperty(cp + "effects", "Glow");
            c.hlColor         = hexToColor(props.getProperty(cp + "hlColor", "#FFC832A0"));
            c.glowSize        = Integer.parseInt(props.getProperty(cp + "glowSize", "7"));
            c.rank            = Integer.parseInt(props.getProperty(cp + "rank", "0"));
            c.playAfterReveal = Boolean.parseBoolean(props.getProperty(cp + "playAfterReveal", "false"));
            tmpl.cues.add(c);
        }

        // Apply to all non-title-grid slides
        isSyncingFormat = true;
        try {
            for (SlideRow row : slideRows) {
                if (row.isTitleGridSlide) continue;
                row.applyFormatting(fontName, fontSize, fontStyle, fontColor, alignment, showPin, displayMode,
                        subtitleY, subtitleBgOpacity, sourceVideoVolume,
                        bgTransparency,
                        showSlideNumber, slideNumberFontName, slideNumberX, slideNumberY, slideNumberSize, slideNumberColor,
                        slideNumberStyle, slideNumberEffect,
                        slideTextFormats, null,
                        fxRoundCorners, fxCornerRadius,
                        fxVignetteOn, fxVignetteVal, fxSepiaOn, fxSepiaVal,
                        fxGrainOn, fxGrainVal, fxWaterRippleOn, fxWaterRippleVal,
                        fxGlitchOn, fxGlitchVal, fxShakeOn, fxShakeVal,
                        fxScanlineOn, fxScanlineVal, fxRaisedOn, fxRaisedVal,
                        fxOtherKind, fxOtherVal,
                        overlayShape, overlayBgMode, overlayBgColor, overlayX, overlayY, overlaySize,
                        textJustify, textWidthPct, highlightText, highlightColor,
                        textShiftX,
                        null, -1, 50, 25, 30, false, false,
                        0.0, audioHlColorList, audioHlEffectsList, audioGlowSizeList,
                        karaokeStyleList, karaokeColorList);
                row.getQuiz().copyVisualSettingsFrom(tmpl);
                row.refreshQuizToolbarFromState();
            }
        } finally {
            isSyncingFormat = false;
        }

        JOptionPane.showMessageDialog(this, "Preset \"" + name + "\" loaded.", "Load Preset", JOptionPane.INFORMATION_MESSAGE);
    }

    private void deletePreset() {
        String name = (String) presetCombo.getSelectedItem();
        if (name == null || name.isEmpty()) {
            JOptionPane.showMessageDialog(this, "No preset selected.", "Delete Preset", JOptionPane.WARNING_MESSAGE);
            return;
        }

        int confirm = JOptionPane.showConfirmDialog(this,
                "Delete preset \"" + name + "\"?", "Delete Preset", JOptionPane.YES_NO_OPTION);
        if (confirm != JOptionPane.YES_OPTION) return;

        File file = new File(PRESETS_DIR, name + ".preset");
        if (file.exists()) file.delete();
        refreshPresetCombo();
    }

    // Arabic script uses cursive shaping: each letter has different glyph forms
    // (initial/medial/final/isolated) chosen by the shaper based on neighbors.
    // Drawing per-character forces every glyph into its isolated form, breaking
    // ligatures. Effects that iterate per char (Water Ripple, Shake) must
    // fall back to a whole-line/word path when this returns true.
    private static boolean containsArabic(String s) {
        if (s == null) return false;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if ((c >= 0x0600 && c <= 0x06FF)
                    || (c >= 0x0750 && c <= 0x077F)
                    || (c >= 0x08A0 && c <= 0x08FF)
                    || (c >= 0xFB50 && c <= 0xFDFF)
                    || (c >= 0xFE70 && c <= 0xFEFF)) {
                return true;
            }
        }
        return false;
    }

    private static String colorToHex(Color c) {
        if (c.getAlpha() == 255) {
            return String.format("#%02X%02X%02X", c.getRed(), c.getGreen(), c.getBlue());
        }
        return String.format("#%02X%02X%02X%02X", c.getRed(), c.getGreen(), c.getBlue(), c.getAlpha());
    }

    private static Color hexToColor(String hex) {
        if (hex == null || hex.isEmpty()) return Color.WHITE;
        hex = hex.startsWith("#") ? hex.substring(1) : hex;
        try {
            if (hex.length() == 6) {
                return new Color(Integer.parseInt(hex, 16));
            } else if (hex.length() == 8) {
                int r = Integer.parseInt(hex.substring(0, 2), 16);
                int g = Integer.parseInt(hex.substring(2, 4), 16);
                int b = Integer.parseInt(hex.substring(4, 6), 16);
                int a = Integer.parseInt(hex.substring(6, 8), 16);
                return new Color(r, g, b, a);
            }
        } catch (NumberFormatException ignored) {}
        return Color.WHITE;
    }

    // ==================== Title Grid Slide ====================

    private void addTitleGridSlide() {
        List<BufferedImage> images = new ArrayList<>();
        for (SlideRow row : slideRows) {
            if (row.getImage() != null && !row.isTitleGridSlide) {
                images.add(row.getImage());
            }
        }

        if (images.isEmpty()) {
            JOptionPane.showMessageDialog(this,
                    "Add images to your slides first.\nThe title grid is built from your slide images.",
                    "No Images", JOptionPane.WARNING_MESSAGE);
            return;
        }

        String titleText = JOptionPane.showInputDialog(this,
                "Enter title text for the grid slide:", "My Slide Show");
        if (titleText == null) return;

        String[] layouts = {
                "1. Auto Grid (even mosaic)",
                "2. Big Center + Surround",
                "3. Big Left + Right Stack",
                "4. Big Right + Left Stack",
                "5. Big Top + Bottom Row",
                "6. Big Bottom + Top Row",
                "7. Center Empty + Border Ring",
                "8. Diagonal Cascade",
                "9. Left Column + Right Grid",
                "10. Checkerboard Scatter"
        };
        String chosen = (String) JOptionPane.showInputDialog(this,
                "Choose grid layout:", "Title Grid Layout",
                JOptionPane.QUESTION_MESSAGE, null, layouts, layouts[0]);
        if (chosen == null) return;
        int layoutIndex = Integer.parseInt(chosen.substring(0, chosen.indexOf('.')).trim());

        BufferedImage gridImage = generateGridImage(images, getOutputWidth(), getOutputHeight(), layoutIndex);

        // Optionally pick a background image
        BufferedImage bgImage = null;
        int bgChoice = JOptionPane.showConfirmDialog(this,
                "Would you like to add a background image?\n" +
                        "The selected display mode effect (Blur-Fit, Fill Crop, etc.)\nwill be applied to it behind the grid.",
                "Background Image", JOptionPane.YES_NO_OPTION, JOptionPane.QUESTION_MESSAGE);
        if (bgChoice == JOptionPane.YES_OPTION) {
            JFileChooser fc = new JFileChooser();
            fc.setFileFilter(new javax.swing.filechooser.FileNameExtensionFilter(
                    "Images (jpg, png, gif, bmp, webp, avif, heif)",
                    "jpg", "jpeg", "png", "gif", "bmp", "webp", "avif", "heif", "heic"));
            if (fc.showOpenDialog(this) == JFileChooser.APPROVE_OPTION) {
                try {
                    bgImage = loadImageFile(fc.getSelectedFile());
                } catch (IOException ex) {
                    JOptionPane.showMessageDialog(this, "Error loading background: " + ex.getMessage(),
                            "Error", JOptionPane.ERROR_MESSAGE);
                }
            }
        }

        slideRows.removeIf(r -> r.isTitleGridSlide);

        SlideRow titleRow = new SlideRow(1);
        titleRow.isTitleGridSlide = true;
        titleRow.gridLayoutIndex = layoutIndex;
        titleRow.gridSourceImages = new ArrayList<>(images);
        titleRow.titleBgImage = bgImage;
        titleRow.setImageDirectly(gridImage, bgImage != null ?
                "📸 Layout " + layoutIndex + " + BG image" :
                "📸 Layout " + layoutIndex + " (" + images.size() + " images)");
        titleRow.setSubtitleText(titleText);
        titleRow.applyFormatting("Segoe UI", 48, Font.BOLD,
                Color.WHITE, SwingConstants.CENTER, false, "Blur-Fit", 5, 78, 25,
                0,
                false, loadedFontNames[0], 50, 10, 80, Color.WHITE,
                "Circle", "None",
                Collections.singletonList(new SlideTextData(false, "", "Segoe UI", 40, Font.PLAIN,
                        Color.YELLOW, 50, 50, 0, Color.BLACK, false, 100, 0, SwingConstants.CENTER)),
                null,
                false, 60, false, 50, false, 100, false, 50, false, 50, false, 50, false, 50,
                false, 50, false, 50,
                "None", 50,
                "Rectangular", "Blur", new Color(21, 32, 43), 50, 50, 20,
                false, 100, "", new Color(255, 255, 0, 180), 0,

                null, -1, 50, 25, 30, false, false,
                0.0, null, null, null, null, null);

        slideRows.add(0, titleRow);
        rebuildSlidesPanel();

        String bgMsg = bgImage != null ? "\nBackground image added — change effect via the display mode dropdown." : "";
        JOptionPane.showMessageDialog(this,
                "Title grid slide created with layout #" + layoutIndex + " and " + images.size() + " images!" + bgMsg,
                "Title Grid Slide", JOptionPane.INFORMATION_MESSAGE);
    }

    // ==================== Grid Image Generation ====================

    private static BufferedImage generateGridImage(List<BufferedImage> images, int targetW, int targetH) {
        return generateGridImage(images, targetW, targetH, 1);
    }

    private static BufferedImage generateGridImage(List<BufferedImage> images, int targetW, int targetH, int layout) {
        BufferedImage grid = new BufferedImage(targetW, targetH, BufferedImage.TYPE_INT_RGB);
        Graphics2D g = grid.createGraphics();
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g.setRenderingHint(RenderingHints.KEY_INTERPOLATION, RenderingHints.VALUE_INTERPOLATION_BICUBIC);
        g.setRenderingHint(RenderingHints.KEY_RENDERING, RenderingHints.VALUE_RENDER_QUALITY);

        g.setColor(new Color(18, 18, 24));
        g.fillRect(0, 0, targetW, targetH);

        int gap = Math.max(6, Math.min(targetW, targetH) / 80);
        int count = images.size();

        List<int[]> cells;
        switch (layout) {
            case 2:  cells = layoutBigCenter(targetW, targetH, gap, count); break;
            case 3:  cells = layoutBigSide(targetW, targetH, gap, count, true); break;
            case 4:  cells = layoutBigSide(targetW, targetH, gap, count, false); break;
            case 5:  cells = layoutBigTopBottom(targetW, targetH, gap, count, true); break;
            case 6:  cells = layoutBigTopBottom(targetW, targetH, gap, count, false); break;
            case 7:  cells = layoutBorderRing(targetW, targetH, gap, count); break;
            case 8:  cells = layoutDiagonalCascade(targetW, targetH, gap, count); break;
            case 9:  cells = layoutColumnGrid(targetW, targetH, gap, count); break;
            case 10: cells = layoutCheckerboard(targetW, targetH, gap, count); break;
            default: cells = layoutAutoGrid(targetW, targetH, gap, count); break;
        }

        for (int i = 0; i < Math.min(count, cells.size()); i++) {
            int[] cell = cells.get(i);
            drawImageInCell(g, images.get(i), cell[0], cell[1], cell[2], cell[3]);
        }

        GradientPaint gradient = new GradientPaint(
                0, targetH * 0.5f, new Color(0, 0, 0, 0),
                0, targetH, new Color(0, 0, 0, 200));
        g.setPaint(gradient);
        g.fillRect(0, (int) (targetH * 0.5), targetW, targetH);

        // Top vignette for polish
        GradientPaint topGrad = new GradientPaint(
                0, 0, new Color(0, 0, 0, 100),
                0, targetH * 0.15f, new Color(0, 0, 0, 0));
        g.setPaint(topGrad);
        g.fillRect(0, 0, targetW, (int) (targetH * 0.15));

        g.dispose();
        return grid;
    }

    private static void drawImageInCell(Graphics2D g, BufferedImage img, int cx, int cy, int cw, int ch) {
        if (cw < 2 || ch < 2) return;

        int radius = Math.min(cw, ch) / 12;
        java.awt.geom.RoundRectangle2D roundRect =
                new java.awt.geom.RoundRectangle2D.Float(cx, cy, cw, ch, radius, radius);

        Shape oldClip = g.getClip();
        g.setClip(roundRect);

        // Fill cell with cover-crop of the image
        double scX = (double) cw / img.getWidth();
        double scY = (double) ch / img.getHeight();
        double coverSc = Math.max(scX, scY);
        int drawW = (int) (img.getWidth() * coverSc);
        int drawH = (int) (img.getHeight() * coverSc);
        g.drawImage(img, cx + (cw - drawW) / 2, cy + (ch - drawH) / 2, drawW, drawH, null);

        g.setClip(oldClip);

        // Subtle border
        Graphics2D g2 = (Graphics2D) g.create();
        g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g2.setColor(new Color(255, 255, 255, 40));
        g2.setStroke(new BasicStroke(1.5f));
        g2.draw(roundRect);
        g2.dispose();
    }

    // ===== Layout 1: Auto Grid =====
    private static List<int[]> layoutAutoGrid(int w, int h, int gap, int count) {
        List<int[]> cells = new ArrayList<>();
        int cols, rows;
        if (count <= 1) { cols = 1; rows = 1; }
        else if (count <= 2) { cols = 2; rows = 1; }
        else if (count <= 4) { cols = 2; rows = 2; }
        else if (count <= 6) { cols = 3; rows = 2; }
        else if (count <= 9) { cols = 3; rows = 3; }
        else if (count <= 12) { cols = 4; rows = 3; }
        else if (count <= 16) { cols = 4; rows = 4; }
        else if (count <= 20) { cols = 5; rows = 4; }
        else if (count <= 25) { cols = 5; rows = 5; }
        else { cols = 6; rows = (int) Math.ceil(count / 6.0); }

        int cw = (w - gap * (cols + 1)) / cols;
        int ch = (h - gap * (rows + 1)) / rows;
        int idx = 0;
        for (int r = 0; r < rows && idx < count; r++) {
            for (int c = 0; c < cols && idx < count; c++) {
                cells.add(new int[]{gap + c * (cw + gap), gap + r * (ch + gap), cw, ch});
                idx++;
            }
        }
        return cells;
    }

    // ===== Layout 2: Big Center + Surround =====
    private static List<int[]> layoutBigCenter(int w, int h, int gap, int count) {
        List<int[]> cells = new ArrayList<>();
        if (count < 2) return layoutAutoGrid(w, h, gap, count);

        int bigW = (int) (w * 0.5);
        int bigH = (int) (h * 0.55);
        int bigX = (w - bigW) / 2;
        int bigY = (h - bigH) / 2;
        cells.add(new int[]{bigX, bigY, bigW, bigH});

        int remaining = count - 1;
        // Distribute evenly around the sides: top, bottom, left, right
        int perSide = Math.max(1, (remaining + 3) / 4);
        int topCount = Math.min(perSide, remaining);
        int bottomCount = Math.min(perSide, remaining - topCount);
        int leftCount = Math.min(perSide, remaining - topCount - bottomCount);
        int rightCount = remaining - topCount - bottomCount - leftCount;

        // Top row
        if (topCount > 0) {
            int slotW = (w - gap * (topCount + 1)) / topCount;
            int slotH = bigY - gap * 2;
            for (int i = 0; i < topCount; i++) {
                cells.add(new int[]{gap + i * (slotW + gap), gap, slotW, Math.max(slotH, 50)});
            }
        }

        // Bottom row
        if (bottomCount > 0) {
            int slotW = (w - gap * (bottomCount + 1)) / bottomCount;
            int slotH = h - (bigY + bigH + gap * 2);
            for (int i = 0; i < bottomCount; i++) {
                cells.add(new int[]{gap + i * (slotW + gap), bigY + bigH + gap, slotW, Math.max(slotH, 50)});
            }
        }

        // Left column
        if (leftCount > 0) {
            int lSlotW = bigX - gap * 2;
            int lSlotH = (bigH - gap * (leftCount - 1)) / leftCount;
            for (int i = 0; i < leftCount; i++) {
                cells.add(new int[]{gap, bigY + i * (lSlotH + gap), Math.max(lSlotW, 50), lSlotH});
            }
        }

        // Right column
        if (rightCount > 0) {
            int rSlotW = w - (bigX + bigW + gap * 2);
            int rSlotH = (bigH - gap * (rightCount - 1)) / rightCount;
            for (int i = 0; i < rightCount; i++) {
                cells.add(new int[]{bigX + bigW + gap, bigY + i * (rSlotH + gap), Math.max(rSlotW, 50), rSlotH});
            }
        }
        return cells;
    }

    // ===== Layout 3/4: Big Left or Big Right + Stack =====
    private static List<int[]> layoutBigSide(int w, int h, int gap, int count, boolean bigOnLeft) {
        List<int[]> cells = new ArrayList<>();
        if (count < 2) return layoutAutoGrid(w, h, gap, count);

        int bigW = (int) (w * 0.55);
        int smallW = w - bigW - gap * 3;
        int remaining = count - 1;

        // If too many, use 2 columns on the small side
        int cols = remaining > 4 ? 2 : 1;
        int rows = (int) Math.ceil((double) remaining / cols);
        int cellW = (smallW - gap * (cols - 1)) / cols;
        int cellH = (h - gap * (rows + 1)) / rows;

        int smallX = bigOnLeft ? bigW + gap * 2 : gap;
        int bigX = bigOnLeft ? gap : w - bigW - gap;

        cells.add(new int[]{bigX, gap, bigW, h - gap * 2});
        int idx = 0;
        for (int r = 0; r < rows && idx < remaining; r++) {
            for (int c = 0; c < cols && idx < remaining; c++) {
                cells.add(new int[]{smallX + c * (cellW + gap), gap + r * (cellH + gap), cellW, cellH});
                idx++;
            }
        }
        return cells;
    }

    // ===== Layout 5/6: Big Top or Big Bottom + Row =====
    private static List<int[]> layoutBigTopBottom(int w, int h, int gap, int count, boolean bigOnTop) {
        List<int[]> cells = new ArrayList<>();
        if (count < 2) return layoutAutoGrid(w, h, gap, count);

        int bigH = (int) (h * 0.55);
        int smallH = h - bigH - gap * 3;
        int remaining = count - 1;

        // If too many, use 2 rows on the small side
        int rows = remaining > 5 ? 2 : 1;
        int cols = (int) Math.ceil((double) remaining / rows);
        int cellW = (w - gap * (cols + 1)) / cols;
        int cellH = (smallH - gap * (rows - 1)) / rows;

        int smallY = bigOnTop ? bigH + gap * 2 : gap;
        int bigY = bigOnTop ? gap : h - bigH - gap;

        cells.add(new int[]{gap, bigY, w - gap * 2, bigH});
        int idx = 0;
        for (int r = 0; r < rows && idx < remaining; r++) {
            for (int c = 0; c < cols && idx < remaining; c++) {
                cells.add(new int[]{gap + c * (cellW + gap), smallY + r * (cellH + gap), cellW, cellH});
                idx++;
            }
        }
        return cells;
    }

    // ===== Layout 7: Center Empty + Border Ring =====
    private static List<int[]> layoutBorderRing(int w, int h, int gap, int count) {
        List<int[]> cells = new ArrayList<>();
        if (count < 4) return layoutAutoGrid(w, h, gap, count);

        int borderSize = Math.min(w, h) / 4;
        int top = Math.max(1, count / 4);
        int bottom = Math.max(1, count / 4);
        int left = Math.max(1, (count - top - bottom) / 2);
        int right = count - top - bottom - left;

        int slotW = top > 0 ? (w - gap * (top + 1)) / top : 0;
        for (int i = 0; i < top; i++) {
            cells.add(new int[]{gap + i * (slotW + gap), gap, slotW, borderSize});
        }

        slotW = bottom > 0 ? (w - gap * (bottom + 1)) / bottom : 0;
        for (int i = 0; i < bottom; i++) {
            cells.add(new int[]{gap + i * (slotW + gap), h - borderSize - gap, slotW, borderSize});
        }

        int midH = h - borderSize * 2 - gap * 4;
        int lSlotH = left > 0 ? (midH - gap * (left - 1)) / left : 0;
        for (int i = 0; i < left; i++) {
            cells.add(new int[]{gap, borderSize + gap * 2 + i * (lSlotH + gap), borderSize, lSlotH});
        }

        int rSlotH = right > 0 ? (midH - gap * (right - 1)) / right : 0;
        for (int i = 0; i < right; i++) {
            cells.add(new int[]{w - borderSize - gap, borderSize + gap * 2 + i * (rSlotH + gap), borderSize, rSlotH});
        }
        return cells;
    }

    // ===== Layout 8: Diagonal Cascade =====
    private static List<int[]> layoutDiagonalCascade(int w, int h, int gap, int count) {
        List<int[]> cells = new ArrayList<>();
        if (count == 0) return cells;

        int cellW = (int) (w * 0.4);
        int cellH = (int) (h * 0.4);
        int stepX = count > 1 ? (w - cellW - gap * 2) / (count - 1) : 0;
        int stepY = count > 1 ? (h - cellH - gap * 2) / (count - 1) : 0;

        for (int i = 0; i < count; i++) {
            cells.add(new int[]{gap + i * stepX, gap + i * stepY, cellW, cellH});
        }
        return cells;
    }

    // ===== Layout 9: Left Column + Right Grid =====
    private static List<int[]> layoutColumnGrid(int w, int h, int gap, int count) {
        List<int[]> cells = new ArrayList<>();
        if (count < 2) return layoutAutoGrid(w, h, gap, count);

        int colW = w / 3 - gap;
        int gridW = w - colW - gap * 3;

        cells.add(new int[]{gap, gap, colW, h - gap * 2});

        int remaining = count - 1;
        int cols = (int) Math.ceil(Math.sqrt(remaining * (double) gridW / (h > 0 ? h : 1)));
        cols = Math.max(1, Math.min(cols, remaining));
        int rows = (int) Math.ceil((double) remaining / cols);

        int slotW = (gridW - gap * (cols - 1)) / cols;
        int slotH = (h - gap * (rows + 1)) / rows;
        int idx = 0;
        for (int r = 0; r < rows && idx < remaining; r++) {
            for (int c = 0; c < cols && idx < remaining; c++) {
                cells.add(new int[]{
                        colW + gap * 2 + c * (slotW + gap),
                        gap + r * (slotH + gap),
                        slotW, slotH
                });
                idx++;
            }
        }
        return cells;
    }

    // ===== Layout 10: Checkerboard Scatter =====
    private static List<int[]> layoutCheckerboard(int w, int h, int gap, int count) {
        List<int[]> cells = new ArrayList<>();
        if (count == 0) return cells;

        int cols = (int) Math.ceil(Math.sqrt(count * 1.5));
        int rows = (int) Math.ceil((double) count / cols);
        cols = Math.max(cols, 1);
        rows = Math.max(rows, 1);

        int slotW = (w - gap * (cols + 1)) / cols;
        int slotH = (h - gap * (rows + 1)) / rows;
        int offsetX = slotW / 4;
        int offsetY = slotH / 4;

        int idx = 0;
        for (int r = 0; r < rows && idx < count; r++) {
            for (int c = 0; c < cols && idx < count; c++) {
                int baseX = gap + c * (slotW + gap);
                int baseY = gap + r * (slotH + gap);
                int ox = (r % 2 == 1) ? offsetX : 0;
                int oy = (c % 2 == 1) ? offsetY / 2 : 0;
                int cx = Math.min(baseX + ox, w - slotW - gap);
                int cy = Math.min(baseY + oy, h - slotH - gap);
                int cw = slotW - Math.abs(ox) / 2;
                int ch = slotH - Math.abs(oy) / 2;
                cells.add(new int[]{Math.max(cx, gap), Math.max(cy, gap), Math.max(cw, 50), Math.max(ch, 50)});
                idx++;
            }
        }
        return cells;
    }

    // ==================== Bulk Import Images ====================

    private void bulkImport() {
        JFileChooser fc = new JFileChooser();
        fc.setMultiSelectionEnabled(true);
        fc.setFileFilter(new FileNameExtensionFilter(
                "Images & Videos (jpg, png, gif, bmp, webp, avif, heif, mp4, mov, webm, mkv, avi, wmv, flv, m4v, mpg)",
                "jpg", "jpeg", "png", "gif", "bmp", "webp", "avif", "heif", "heic",
                "mp4", "avi", "mov", "mkv", "webm", "flv", "wmv", "m4v", "mpg", "mpeg"));
        if (fc.showOpenDialog(this) != JFileChooser.APPROVE_OPTION) return;

        File[] files = fc.getSelectedFiles();
        if (files.length == 0) return;

        Arrays.sort(files, (a, b) -> {
            int numA = extractLeadingNumber(a.getName());
            int numB = extractLeadingNumber(b.getName());
            if (numA != Integer.MAX_VALUE || numB != Integer.MAX_VALUE) {
                return Integer.compare(numA, numB);
            }
            return a.getName().compareToIgnoreCase(b.getName());
        });

        // Modes:
        //   0 = Add to existing   — fill slides that have no photo; leave photo-bearing slides alone.
        //   1 = Overwrite all     — replace only the photo on each eligible slide; keep texts/controls/settings.
        //   2 = Fresh             — no existing content; build from scratch.
        // In modes 0/1 we skip title-grid slides and video slides. Extra files beyond
        // the existing slots are appended as new slides.
        boolean hasContent = slideRows.size() > 1
                || (slideRows.size() == 1 && (slideRows.get(0).getImage() != null || slideRows.get(0).isTitleGridSlide));
        int mode = 2;
        if (hasContent) {
            String[] options = {"Add to existing", "Overwrite all"};
            int choice = JOptionPane.showOptionDialog(this,
                    "You have " + slideRows.size() + " existing slide(s).\nHow would you like to import?",
                    "Bulk Import", JOptionPane.DEFAULT_OPTION, JOptionPane.QUESTION_MESSAGE,
                    null, options, options[0]);
            if (choice < 0) return;
            mode = choice;
        } else {
            // Single empty slide — just clear it
            slideRows.clear();
            slidesPanel.removeAll();
        }

        int loaded = 0;
        int failed = 0;
        int videos = 0;
        int fileIdx = 0;

        if (mode == 0 || mode == 1) {
            for (int i = 0; i < slideRows.size() && fileIdx < files.length; i++) {
                SlideRow row = slideRows.get(i);
                if (row.isTitleGridSlide) continue;
                if (row.getSourceVideoFile() != null) continue;
                if (mode == 0 && row.getImage() != null) continue;

                while (fileIdx < files.length) {
                    File file = files[fileIdx++];
                    try {
                        if (isVideoFile(file)) {
                            int durationMs = probeAudioDurationMs(file);
                            if (durationMs <= 0) { failed++; continue; }
                            BufferedImage firstFrame = extractFirstVideoFrame(file);
                            if (firstFrame == null) { failed++; continue; }
                            row.setVideoSlideDirectly(file, firstFrame, durationMs);
                            loaded++;
                            videos++;
                        } else {
                            BufferedImage img = loadImageFile(file);
                            if (img == null) { failed++; continue; }
                            row.setImageDirectly(img, file.getName());
                            loaded++;
                        }
                        break;
                    } catch (IOException ex) {
                        failed++;
                    }
                }
            }
        }

        while (fileIdx < files.length) {
            File file = files[fileIdx++];
            try {
                if (isVideoFile(file)) {
                    int durationMs = probeAudioDurationMs(file);
                    if (durationMs <= 0) { failed++; continue; }
                    BufferedImage firstFrame = extractFirstVideoFrame(file);
                    if (firstFrame == null) { failed++; continue; }
                    SlideRow row = new SlideRow(slideRows.size() + 1);
                    row.setVideoSlideDirectly(file, firstFrame, durationMs);
                    slideRows.add(row);
                    slidesPanel.add(row.getPanel());
                    slidesPanel.add(Box.createRigidArea(new Dimension(0, 10)));
                    loaded++;
                    videos++;
                } else {
                    BufferedImage img = loadImageFile(file);
                    if (img == null) { failed++; continue; }
                    SlideRow row = new SlideRow(slideRows.size() + 1);
                    row.setImageDirectly(img, file.getName());
                    slideRows.add(row);
                    slidesPanel.add(row.getPanel());
                    slidesPanel.add(Box.createRigidArea(new Dimension(0, 10)));
                    loaded++;
                }
            } catch (IOException ex) {
                failed++;
            }
        }

        // Only broadcast first-slide formatting when building from scratch. In Add/Overwrite
        // modes, each existing slide's texts/controls/settings must remain intact.
        if (mode == 2) {
            applyFirstSlideFormattingToAll();
        }
        slidesPanel.revalidate();
        slidesPanel.repaint();

        int images = loaded - videos;
        String msg = loaded + " item(s) imported successfully ("
                + images + " image(s), " + videos + " video(s)).";
        if (failed > 0) msg += "\n" + failed + " file(s) failed to load.";
        JOptionPane.showMessageDialog(this, msg, "Bulk Import", JOptionPane.INFORMATION_MESSAGE);
    }

    // ==================== Bulk Import Text ====================

    private void bulkImportText() {
        // First ask: import to Subtitle Text or Slide Text?
        String[] targetOptions = {"Subtitle Text (Normal)", "Slide Text"};
        int targetChoice = JOptionPane.showOptionDialog(this,
                "Where do you want to import the text?",
                "Bulk Import Text", JOptionPane.DEFAULT_OPTION, JOptionPane.QUESTION_MESSAGE,
                null, targetOptions, targetOptions[0]);

        if (targetChoice < 0) return;

        boolean importToSlideText = (targetChoice == 1);

        // Then ask: from file or clipboard?
        String[] options = {"From File (.txt)", "From Clipboard / Paste"};
        int choice = JOptionPane.showOptionDialog(this,
                "Import text lines (one line per slide).\nLine 1 → Slide 1, Line 2 → Slide 2, etc.\n(Title grid slide is skipped)",
                "Bulk Import Text", JOptionPane.DEFAULT_OPTION, JOptionPane.QUESTION_MESSAGE,
                null, options, options[0]);

        if (choice < 0) return;

        List<String> lines;

        if (choice == 0) {
            JFileChooser fc = new JFileChooser();
            fc.setFileFilter(new FileNameExtensionFilter("Text files (*.txt)", "txt"));
            if (fc.showOpenDialog(this) != JFileChooser.APPROVE_OPTION) return;

            try {
                byte[] fileBytes = Files.readAllBytes(fc.getSelectedFile().toPath());
                int off = 0;
                String content = null;
                // Strip UTF-8 BOM if present
                if (fileBytes.length >= 3 && (fileBytes[0] & 0xFF) == 0xEF
                        && (fileBytes[1] & 0xFF) == 0xBB && (fileBytes[2] & 0xFF) == 0xBF) {
                    off = 3;
                }
                // UTF-16 LE BOM
                else if (fileBytes.length >= 2 && (fileBytes[0] & 0xFF) == 0xFF && (fileBytes[1] & 0xFF) == 0xFE) {
                    content = new String(fileBytes, java.nio.charset.Charset.forName("UTF-16LE"));
                    if (content.length() > 0 && content.charAt(0) == '\uFEFF') content = content.substring(1);
                }
                // UTF-16 BE BOM
                else if (fileBytes.length >= 2 && (fileBytes[0] & 0xFF) == 0xFE && (fileBytes[1] & 0xFF) == 0xFF) {
                    content = new String(fileBytes, java.nio.charset.Charset.forName("UTF-16BE"));
                    if (content.length() > 0 && content.charAt(0) == '\uFEFF') content = content.substring(1);
                }
                if (content == null) {
                    content = new String(fileBytes, off, fileBytes.length - off, StandardCharsets.UTF_8);
                    // If UTF-8 produced replacement chars, try Windows-1252
                    if (content.contains("\uFFFD")) {
                        content = new String(fileBytes, off, fileBytes.length - off,
                                java.nio.charset.Charset.forName("windows-1252"));
                    }
                }
                lines = Arrays.asList(content.split("\\r?\\n"));
            } catch (IOException ex) {
                try {
                    lines = Files.readAllLines(fc.getSelectedFile().toPath());
                } catch (IOException ex2) {
                    JOptionPane.showMessageDialog(this,
                            "Failed to read file:\n" + ex2.getMessage(),
                            "Error", JOptionPane.ERROR_MESSAGE);
                    return;
                }
            }
        } else {
            JTextArea pasteArea = new JTextArea(12, 40);
            pasteArea.setFont(new Font("Segoe UI", Font.PLAIN, 14));
            pasteArea.setLineWrap(true);
            pasteArea.setWrapStyleWord(true);
            JScrollPane sp = new JScrollPane(pasteArea);
            sp.setPreferredSize(new Dimension(500, 300));

            int result = JOptionPane.showConfirmDialog(this, sp,
                    "Paste text (one line per slide):",
                    JOptionPane.OK_CANCEL_OPTION, JOptionPane.PLAIN_MESSAGE);
            if (result != JOptionPane.OK_OPTION) return;

            String text = pasteArea.getText();
            if (text.trim().isEmpty()) {
                JOptionPane.showMessageDialog(this, "No text entered.", "Empty", JOptionPane.WARNING_MESSAGE);
                return;
            }
            lines = Arrays.asList(text.split("\\r?\\n"));
        }

        ArrayList<String> trimmed = new ArrayList<>(lines);
        while (!trimmed.isEmpty() && trimmed.get(trimmed.size() - 1).trim().isEmpty()) {
            trimmed.remove(trimmed.size() - 1);
        }
        lines = trimmed;

        if (lines.isEmpty()) {
            JOptionPane.showMessageDialog(this, "No text lines found.", "Empty", JOptionPane.WARNING_MESSAGE);
            return;
        }

        List<SlideRow> targetSlides = new ArrayList<>();
        for (SlideRow row : slideRows) {
            if (!row.isTitleGridSlide) {
                targetSlides.add(row);
            }
        }

        int assigned = 0;
        for (int i = 0; i < lines.size(); i++) {
            String line = lines.get(i).trim();
            if (i < targetSlides.size()) {
                if (importToSlideText) {
                    targetSlides.get(i).setSlideText(line);
                } else {
                    targetSlides.get(i).setSubtitleText(line);
                }
            } else {
                SlideRow row = new SlideRow(slideRows.size() + 1);
                if (importToSlideText) {
                    row.setSlideText(line);
                } else {
                    row.setSubtitleText(line);
                }
                slideRows.add(row);
                slidesPanel.add(row.getPanel());
                slidesPanel.add(Box.createRigidArea(new Dimension(0, 10)));
            }
            assigned++;
        }

        applyFirstSlideFormattingToAll();
        slidesPanel.revalidate();
        slidesPanel.repaint();

        String targetLabel = importToSlideText ? "slide text" : "subtitle text";
        JOptionPane.showMessageDialog(this,
                assigned + " lines assigned to " + targetLabel + ".\nSlides: " + slideRows.size() + " total.",
                "Bulk Text Import", JOptionPane.INFORMATION_MESSAGE);
    }

    // ==================== Dictionary Import ====================

    /**
     * Splits raw CSV/TSV content into logical rows, respecting quoted fields
     * that may contain newlines (multiline cells). A quoted field like
     * "line1\nline2\nline3" is kept as a single field value.
     */
    private List<String> splitCsvRows(String content) {
        List<String> rows = new ArrayList<>();
        StringBuilder currentRow = new StringBuilder();
        boolean inQuotes = false;
        for (int i = 0; i < content.length(); i++) {
            char c = content.charAt(i);
            if (inQuotes) {
                if (c == '"') {
                    if (i + 1 < content.length() && content.charAt(i + 1) == '"') {
                        // Escaped quote
                        currentRow.append('"').append('"');
                        i++;
                    } else {
                        inQuotes = false;
                        currentRow.append(c);
                    }
                } else {
                    currentRow.append(c);
                }
            } else {
                if (c == '"') {
                    inQuotes = true;
                    currentRow.append(c);
                } else if (c == '\r') {
                    // Skip \r, handle \n next
                } else if (c == '\n') {
                    rows.add(currentRow.toString());
                    currentRow.setLength(0);
                } else {
                    currentRow.append(c);
                }
            }
        }
        // Add last row if non-empty
        if (currentRow.length() > 0) {
            rows.add(currentRow.toString());
        }
        return rows;
    }

    private List<String> parseCsvLine(String line) {
        List<String> fields = new ArrayList<>();
        StringBuilder sb = new StringBuilder();
        boolean inQuotes = false;
        for (int i = 0; i < line.length(); i++) {
            char c = line.charAt(i);
            if (inQuotes) {
                if (c == '"') {
                    if (i + 1 < line.length() && line.charAt(i + 1) == '"') {
                        sb.append('"');
                        i++;
                    } else {
                        inQuotes = false;
                    }
                } else {
                    sb.append(c);
                }
            } else {
                if (c == '"') {
                    inQuotes = true;
                } else if (c == ',' || c == '\t') {
                    fields.add(sb.toString().trim());
                    sb.setLength(0);
                } else {
                    sb.append(c);
                }
            }
        }
        fields.add(sb.toString().trim());
        return fields;
    }

    private void dictionaryImport() {
        // Choose source: file or clipboard
        String[] options = {"From File (CSV/TSV)", "From Clipboard / Paste"};
        int choice = JOptionPane.showOptionDialog(this,
                "Import dictionary: each row = one slide, each column = one slide text.\n"
                        + "Column A → Text 1, Column B → Text 2, Column C → Text 3, etc.\n"
                        + "Supports CSV (comma) and TSV (tab) delimited files.\n"
                        + "Tip: For Unicode/IPA characters, save from Excel as \"CSV UTF-8\" format.\n"
                        + "Optional columns: X-AXIS, Y-AXIS, TEXT-SIZE (comma-separated per text item).\n"
                        + "(Title grid slides are skipped)",
                "Dictionary Import", JOptionPane.DEFAULT_OPTION, JOptionPane.QUESTION_MESSAGE,
                null, options, options[0]);

        if (choice < 0) return;

        List<String> rawLines = null;
        File importSourceDir = null; // directory of imported file, for resolving relative paths

        if (choice == 0) {
            JFileChooser fc = new JFileChooser();
            fc.setFileFilter(new FileNameExtensionFilter(
                    "CSV / TSV files (*.csv, *.tsv, *.txt)", "csv", "tsv", "txt"));
            if (fc.showOpenDialog(this) != JFileChooser.APPROVE_OPTION) return;
            importSourceDir = fc.getSelectedFile().getParentFile();

            try {
                // Try UTF-8 first (handles BOM automatically via readAllLines)
                byte[] fileBytes = Files.readAllBytes(fc.getSelectedFile().toPath());
                // Strip UTF-8 BOM if present
                int offset = 0;
                if (fileBytes.length >= 3 && (fileBytes[0] & 0xFF) == 0xEF
                        && (fileBytes[1] & 0xFF) == 0xBB && (fileBytes[2] & 0xFF) == 0xBF) {
                    offset = 3;
                }
                // Strip UTF-16 LE BOM
                else if (fileBytes.length >= 2 && (fileBytes[0] & 0xFF) == 0xFF && (fileBytes[1] & 0xFF) == 0xFE) {
                    String content = new String(fileBytes, java.nio.charset.Charset.forName("UTF-16LE"));
                    // Remove BOM character
                    if (content.length() > 0 && content.charAt(0) == '\uFEFF') content = content.substring(1);
                    rawLines = splitCsvRows(content);
                    offset = -1; // signal already decoded
                }
                // Strip UTF-16 BE BOM
                else if (fileBytes.length >= 2 && (fileBytes[0] & 0xFF) == 0xFE && (fileBytes[1] & 0xFF) == 0xFF) {
                    String content = new String(fileBytes, java.nio.charset.Charset.forName("UTF-16BE"));
                    if (content.length() > 0 && content.charAt(0) == '\uFEFF') content = content.substring(1);
                    rawLines = splitCsvRows(content);
                    offset = -1;
                }
                if (offset >= 0) {
                    String content = new String(fileBytes, offset, fileBytes.length - offset, StandardCharsets.UTF_8);
                    // Check if UTF-8 decoded cleanly (no replacement chars)
                    if (content.contains("\uFFFD")) {
                        // Try Windows-1252 (common Excel encoding) which supports accented chars
                        content = new String(fileBytes, offset, fileBytes.length - offset,
                                java.nio.charset.Charset.forName("windows-1252"));
                    }
                    rawLines = splitCsvRows(content);
                }
            } catch (IOException ex) {
                try {
                    rawLines = Files.readAllLines(fc.getSelectedFile().toPath());
                } catch (IOException ex2) {
                    JOptionPane.showMessageDialog(this,
                            "Failed to read file:\n" + ex2.getMessage(),
                            "Error", JOptionPane.ERROR_MESSAGE);
                    return;
                }
            }
        } else {
            JTextArea pasteArea = new JTextArea(12, 50);
            pasteArea.setFont(new Font("Segoe UI", Font.PLAIN, 14));
            pasteArea.setLineWrap(false);
            JScrollPane sp = new JScrollPane(pasteArea);
            sp.setPreferredSize(new Dimension(600, 300));

            int result = JOptionPane.showConfirmDialog(this, sp,
                    "Paste CSV/TSV data (rows = slides, columns = text items):",
                    JOptionPane.OK_CANCEL_OPTION, JOptionPane.PLAIN_MESSAGE);
            if (result != JOptionPane.OK_OPTION) return;

            String text = pasteArea.getText();
            if (text.trim().isEmpty()) {
                JOptionPane.showMessageDialog(this, "No data entered.", "Empty", JOptionPane.WARNING_MESSAGE);
                return;
            }
            rawLines = splitCsvRows(text);
        }

        // Remove trailing empty lines
        ArrayList<String> trimmed = new ArrayList<>(rawLines);
        while (!trimmed.isEmpty() && trimmed.get(trimmed.size() - 1).trim().isEmpty()) {
            trimmed.remove(trimmed.size() - 1);
        }

        if (trimmed.isEmpty()) {
            JOptionPane.showMessageDialog(this, "No data rows found.", "Empty", JOptionPane.WARNING_MESSAGE);
            return;
        }

        // Ask whether first row is a header
        int headerChoice = JOptionPane.showOptionDialog(this,
                "Does the first row contain column headers?\n(If yes, it will be skipped.\nUse HL/UL/BOLD/ITALIC/COLOR headers for formatting,\nAUDIOLINK for slide audio, AUDIO1/AUDIO2/... for multi-audio per text.\nX-AXIS/Y-AXIS/TEXT-SIZE for position & size per text item.)",
                "Dictionary Import", JOptionPane.YES_NO_OPTION, JOptionPane.QUESTION_MESSAGE,
                null, new String[]{"Yes, skip first row", "No, first row is data"}, "No, first row is data");

        // Detect HL/UL/BOLD/ITALIC/COLOR/AUDIOLINK columns from header row
        int hlColIndex = -1;
        int ulColIndex = -1;
        int boldColIndex = -1;
        int italicColIndex = -1;
        int colorColIndex = -1;
        int audioLinkColIndex = -1;
        int xAxisColIndex = -1;
        int yAxisColIndex = -1;
        int textSizeColIndex = -1;
        // Multi-audio: AUDIO1, AUDIO2, AUDIOLINK1, AUDIOLINK2, etc.
        java.util.Map<Integer, Integer> audioColByTextIndex = new java.util.TreeMap<>();
        List<String> headerFields = null;

        List<String> dataLines;
        if (headerChoice == 0) {
            headerFields = parseCsvLine(trimmed.get(0));
            // Scan headers for HL, UL, BOLD, ITALIC, COLOR, and AUDIOLINK columns (case-insensitive)
            for (int c = 0; c < headerFields.size(); c++) {
                String h = headerFields.get(c).trim().toUpperCase();
                if (h.equals("HL") || h.equals("HIGHLIGHT")) {
                    hlColIndex = c;
                } else if (h.equals("UL") || h.equals("UNDERLINE")) {
                    ulColIndex = c;
                } else if (h.equals("BOLD") || h.equals("B")) {
                    boldColIndex = c;
                } else if (h.equals("ITALIC") || h.equals("I")) {
                    italicColIndex = c;
                } else if (h.equals("COLOR") || h.equals("CLR") || h.equals("COLOUR")) {
                    colorColIndex = c;
                } else if (h.equals("AUDIOLINK") || h.equals("AUDIO") || h.equals("AUDIO_LINK")) {
                    audioLinkColIndex = c;
                } else if (h.equals("X-AXIS") || h.equals("XAXIS") || h.equals("X_AXIS")) {
                    xAxisColIndex = c;
                } else if (h.equals("Y-AXIS") || h.equals("YAXIS") || h.equals("Y_AXIS")) {
                    yAxisColIndex = c;
                } else if (h.equals("TEXT-SIZE") || h.equals("TEXTSIZE") || h.equals("TEXT_SIZE") || h.equals("SIZE")) {
                    textSizeColIndex = c;
                } else if (h.matches("(AUDIOLINK|AUDIO|AUDIO_LINK)\\d+")) {
                    // Multi-audio columns: AUDIO1, AUDIO2, AUDIOLINK1, AUDIOLINK2, etc.
                    String numPart = h.replaceAll("^(AUDIOLINK|AUDIO_LINK|AUDIO)", "");
                    int textIdx = Integer.parseInt(numPart) - 1; // 1-based to 0-based
                    if (textIdx >= 0) {
                        audioColByTextIndex.put(textIdx, c);
                    }
                }
            }
            dataLines = trimmed.subList(1, trimmed.size());
        } else {
            dataLines = trimmed;
        }

        if (dataLines.isEmpty()) {
            JOptionPane.showMessageDialog(this, "No data rows after header.", "Empty", JOptionPane.WARNING_MESSAGE);
            return;
        }

        // Build list of text column indices (excluding HL/UL)
        // Parse all rows first to determine max columns
        List<List<String>> allRows = new ArrayList<>();
        int maxCols = 0;
        for (String line : dataLines) {
            List<String> fields = parseCsvLine(line);
            allRows.add(fields);
            maxCols = Math.max(maxCols, fields.size());
        }

        // Determine which columns are text columns (not HL/UL/BOLD/ITALIC/COLOR/AUDIOLINK)
        java.util.Set<Integer> audioColIndices = new java.util.HashSet<>(audioColByTextIndex.values());
        List<Integer> textColIndices = new ArrayList<>();
        for (int c = 0; c < maxCols; c++) {
            if (c != hlColIndex && c != ulColIndex && c != boldColIndex
                    && c != italicColIndex && c != colorColIndex && c != audioLinkColIndex
                    && c != xAxisColIndex && c != yAxisColIndex && c != textSizeColIndex
                    && !audioColIndices.contains(c)) {
                textColIndices.add(c);
            }
        }

        // Collect non-title-grid slides
        List<SlideRow> targetSlides = new ArrayList<>();
        for (SlideRow row : slideRows) {
            if (!row.isTitleGridSlide) {
                targetSlides.add(row);
            }
        }

        int assigned = 0;
        List<String> missingAudioFiles = new ArrayList<>();
        for (int i = 0; i < allRows.size(); i++) {
            List<String> fields = allRows.get(i);
            SlideRow slide;
            if (i < targetSlides.size()) {
                slide = targetSlides.get(i);
            } else {
                // Create new slide
                slide = new SlideRow(slideRows.size() + 1);
                slideRows.add(slide);
                slidesPanel.add(slide.getPanel());
                slidesPanel.add(Box.createRigidArea(new Dimension(0, 10)));
                targetSlides.add(slide);
            }

            // Assign text columns to slide text items (skipping HL/UL columns)
            for (int ti = 0; ti < textColIndices.size(); ti++) {
                int col = textColIndices.get(ti);
                if (col < fields.size()) {
                    String cellText = fields.get(col);
                    if (!cellText.isEmpty()) {
                        slide.setSlideTextAt(ti, cellText);
                    }
                }
            }

            // Apply HL text from CSV if column exists
            if (hlColIndex >= 0 && hlColIndex < fields.size()) {
                String hlText = fields.get(hlColIndex).trim();
                slide.setHighlightText(hlText);
                slide.setSlideTextHighlightText(hlText);
            }

            // Apply UL text from CSV if column exists
            if (ulColIndex >= 0 && ulColIndex < fields.size()) {
                String ulText = fields.get(ulColIndex).trim();
                slide.setSlideTextUnderlineText(ulText);
            }

            // Apply Bold text from CSV if column exists
            if (boldColIndex >= 0 && boldColIndex < fields.size()) {
                String boldText = fields.get(boldColIndex).trim();
                slide.setSlideTextBoldText(boldText);
            }

            // Apply Italic text from CSV if column exists
            if (italicColIndex >= 0 && italicColIndex < fields.size()) {
                String italicText = fields.get(italicColIndex).trim();
                slide.setSlideTextItalicText(italicText);
            }

            // Apply Color text from CSV if column exists
            if (colorColIndex >= 0 && colorColIndex < fields.size()) {
                String colorText = fields.get(colorColIndex).trim();
                slide.setSlideTextColorText(colorText);
            }

            // Apply X-AXIS values from CSV if column exists (comma-separated per text item)
            if (xAxisColIndex >= 0 && xAxisColIndex < fields.size()) {
                String xVals = fields.get(xAxisColIndex).trim();
                if (!xVals.isEmpty()) {
                    String[] parts = xVals.split(",");
                    for (int ti = 0; ti < parts.length; ti++) {
                        String val = parts[ti].trim();
                        if (!val.isEmpty()) {
                            try {
                                int xVal = Integer.parseInt(val);
                                slide.setSlideTextXAt(ti, xVal);
                            } catch (NumberFormatException ignored) {}
                        }
                    }
                }
            }

            // Apply Y-AXIS values from CSV if column exists (comma-separated per text item)
            if (yAxisColIndex >= 0 && yAxisColIndex < fields.size()) {
                String yVals = fields.get(yAxisColIndex).trim();
                if (!yVals.isEmpty()) {
                    String[] parts = yVals.split(",");
                    for (int ti = 0; ti < parts.length; ti++) {
                        String val = parts[ti].trim();
                        if (!val.isEmpty()) {
                            try {
                                int yVal = Integer.parseInt(val);
                                slide.setSlideTextYAt(ti, yVal);
                            } catch (NumberFormatException ignored) {}
                        }
                    }
                }
            }

            // Apply TEXT-SIZE values from CSV if column exists (comma-separated per text item)
            if (textSizeColIndex >= 0 && textSizeColIndex < fields.size()) {
                String sizeVals = fields.get(textSizeColIndex).trim();
                if (!sizeVals.isEmpty()) {
                    String[] parts = sizeVals.split(",");
                    for (int ti = 0; ti < parts.length; ti++) {
                        String val = parts[ti].trim();
                        if (!val.isEmpty()) {
                            try {
                                int sizeVal = Integer.parseInt(val);
                                slide.setSlideTextSizeAt(ti, sizeVal);
                            } catch (NumberFormatException ignored) {}
                        }
                    }
                }
            }

            // Apply audio link from CSV if column exists (single AUDIOLINK → text index 0)
            if (audioLinkColIndex >= 0 && audioLinkColIndex < fields.size()) {
                String audioPath = fields.get(audioLinkColIndex).trim();
                if (!audioPath.isEmpty()) {
                    File audioFile = new File(audioPath);
                    if (!audioFile.isAbsolute() && importSourceDir != null) {
                        audioFile = new File(importSourceDir, audioPath);
                    }
                    if (audioFile.exists()) {
                        int durationMs = probeAudioDurationMs(audioFile);
                        if (durationMs <= 0) durationMs = 3000; // fallback 3s if probe fails
                        slide.setSlideAudio(0, audioFile, durationMs);
                    } else {
                        missingAudioFiles.add("Slide " + (i + 1) + ": " + audioPath);
                    }
                }
            }

            // Apply multi-audio columns (AUDIO1, AUDIO2, etc.)
            for (java.util.Map.Entry<Integer, Integer> entry : audioColByTextIndex.entrySet()) {
                int textIdx = entry.getKey();
                int colIdx = entry.getValue();
                if (colIdx < fields.size()) {
                    String audioPath = fields.get(colIdx).trim();
                    if (!audioPath.isEmpty()) {
                        File audioFile = new File(audioPath);
                        if (!audioFile.isAbsolute() && importSourceDir != null) {
                            audioFile = new File(importSourceDir, audioPath);
                        }
                        if (audioFile.exists()) {
                            int durationMs = probeAudioDurationMs(audioFile);
                            if (durationMs <= 0) durationMs = 3000; // fallback 3s if probe fails
                            slide.setSlideAudio(textIdx, audioFile, durationMs);
                        } else {
                            missingAudioFiles.add("Slide " + (i + 1) + " Text" + (textIdx + 1) + ": " + audioPath);
                        }
                    }
                }
            }

            assigned++;
        }

        applyFirstSlideFormattingToAll();
        slidesPanel.revalidate();
        slidesPanel.repaint();

        String importMsg = assigned + " rows imported across " + textColIndices.size() + " text columns.";
        if (hlColIndex >= 0) importMsg += "\nHL column detected — highlight words imported per slide.";
        if (ulColIndex >= 0) importMsg += "\nUL column detected — underline words imported per slide.";
        if (boldColIndex >= 0) importMsg += "\nBOLD column detected — bold words imported per slide.";
        if (italicColIndex >= 0) importMsg += "\nITALIC column detected — italic words imported per slide.";
        if (colorColIndex >= 0) importMsg += "\nCOLOR column detected — color words imported per slide.";
        if (audioLinkColIndex >= 0) importMsg += "\nAUDIOLINK column detected — audio files imported per slide.";
        if (!audioColByTextIndex.isEmpty()) importMsg += "\nMulti-audio columns detected (AUDIO1-" + (audioColByTextIndex.size()) + ") — audio files mapped to text items.";
        if (xAxisColIndex >= 0) importMsg += "\nX-AXIS column detected — X positions imported per text item.";
        if (yAxisColIndex >= 0) importMsg += "\nY-AXIS column detected — Y positions imported per text item.";
        if (textSizeColIndex >= 0) importMsg += "\nTEXT-SIZE column detected — text sizes imported per text item.";
        importMsg += "\nSlides: " + slideRows.size() + " total.";
        if (!missingAudioFiles.isEmpty()) {
            importMsg += "\n\nWARNING: " + missingAudioFiles.size() + " audio file(s) not found:";
            for (String missing : missingAudioFiles) {
                importMsg += "\n  " + missing;
            }
            importMsg += "\n\nMake sure audio files exist relative to the CSV file location.";
        }
        JOptionPane.showMessageDialog(this, importMsg, "Dictionary Import",
                missingAudioFiles.isEmpty() ? JOptionPane.INFORMATION_MESSAGE : JOptionPane.WARNING_MESSAGE);
    }

    // ==================== Quiz Import ====================

    /**
     * Bulk-load quiz settings from a CSV/TSV file or pasted text. Mirrors the
     * Dict Import UX (file picker or paste, UTF-8/UTF-16/Windows-1252,
     * row N → slide N, title-grid slides skipped). Required: a header row
     * naming the QUIZ_* columns. Empty cells leave the existing value alone.
     * Shared visual / timer-style fields are read from the first data row
     * and broadcast to every non-title-grid slide (mirroring how presets
     * apply visual settings at line 591).
     */
    private void quizImport() {
        String[] options = {"From File (CSV/TSV)", "From Clipboard / Paste"};
        int choice = JOptionPane.showOptionDialog(this,
                "Import quiz settings: each row = one slide.\n"
                        + "Header row REQUIRED. Optional column names (case-insensitive):\n"
                        + "  TEXT1, TEXT2, … TEXTn  -> slide-text items (Text 1, Text 2, …)\n"
                        + "  HL                      -> highlight text (applied to slide and all texts)\n"
                        + "  QUIZ_ENABLED, QUIZ_CORRECT, QUIZ_SECONDS, QUIZ_RED_THRESHOLD,\n"
                        + "  QUIZ_TICK, QUIZ_DING, QUIZ_QUESTION_AUDIO,\n"
                        + "  QUIZ_TIMER_STYLE, QUIZ_TIMER_X, QUIZ_TIMER_Y,\n"
                        + "  QUIZ_TIMER_SIZE, QUIZ_TIMER_WIDTH, QUIZ_TIMER_COLOR,\n"
                        + "  QUIZ_BAR_SHAPE (Rounded/Square/Pill/Segmented),\n"
                        + "  QUIZ_TIMER_TEXT_COLOR, QUIZ_TIMER_FONT,\n"
                        + "  QUIZ_TIMER_LABEL, QUIZ_TIMER_START_MODE,\n"
                        + "  QUIZ_REVEAL_MARK_STYLE (Check/Star/Crown/Trophy/Heart/Thumbs Up/None),\n"
                        + "  QUIZ_REVEAL_MARK_SIZE (50..200), QUIZ_REVEAL_MARK_COLOR,\n"
                        + "  QUIZ_REVEAL_PAD (50..200),\n"
                        + "  QUIZ_TIMER_ANIM (Pulse/Spin/Bounce/Shake/None),\n"
                        + "  QUIZ_TIMER_ANIM_STRENGTH (0..200),\n"
                        + "  QUIZ_TIMER_ANIM_TRIGGER (Red Phase/Always/Each Tick/Never),\n"
                        + "  QUIZ_TIMER_ANIM_EASING (Linear/Ease In/Ease Out/Ease In Out/Bounce),\n"
                        + "  QUIZ_TIMER_RED_COLOR.\n"
                        + "  Available QUIZ_TIMER_STYLE values: Number Circle, Progress Bar H,\n"
                        + "  Progress Bar V, Ring Arc, Analog Clock, Hourglass, Flip Clock,\n"
                        + "  Bomb Fuse, Dot Grid.\n"
                        + "Empty cell = leave that value unchanged.\n"
                        + "Visual / style fields are taken from the FIRST data row and\n"
                        + "applied to all slides.\n"
                        + "Tip: For Unicode/IPA, save Excel as \"CSV UTF-8\".\n"
                        + "(Title grid slides are skipped.)",
                "Quiz Import", JOptionPane.DEFAULT_OPTION, JOptionPane.QUESTION_MESSAGE,
                null, options, options[0]);

        if (choice < 0) return;

        List<String> rawLines = null;
        File importSourceDir = null;

        if (choice == 0) {
            JFileChooser fc = new JFileChooser();
            fc.setFileFilter(new FileNameExtensionFilter(
                    "CSV / TSV files (*.csv, *.tsv, *.txt)", "csv", "tsv", "txt"));
            if (fc.showOpenDialog(this) != JFileChooser.APPROVE_OPTION) return;
            importSourceDir = fc.getSelectedFile().getParentFile();

            try {
                byte[] fileBytes = Files.readAllBytes(fc.getSelectedFile().toPath());
                int offset = 0;
                if (fileBytes.length >= 3 && (fileBytes[0] & 0xFF) == 0xEF
                        && (fileBytes[1] & 0xFF) == 0xBB && (fileBytes[2] & 0xFF) == 0xBF) {
                    offset = 3;
                } else if (fileBytes.length >= 2 && (fileBytes[0] & 0xFF) == 0xFF
                        && (fileBytes[1] & 0xFF) == 0xFE) {
                    String content = new String(fileBytes,
                            java.nio.charset.Charset.forName("UTF-16LE"));
                    if (content.length() > 0 && content.charAt(0) == '\uFEFF') {
                        content = content.substring(1);
                    }
                    rawLines = splitCsvRows(content);
                    offset = -1;
                } else if (fileBytes.length >= 2 && (fileBytes[0] & 0xFF) == 0xFE
                        && (fileBytes[1] & 0xFF) == 0xFF) {
                    String content = new String(fileBytes,
                            java.nio.charset.Charset.forName("UTF-16BE"));
                    if (content.length() > 0 && content.charAt(0) == '\uFEFF') {
                        content = content.substring(1);
                    }
                    rawLines = splitCsvRows(content);
                    offset = -1;
                }
                if (offset >= 0) {
                    String content = new String(fileBytes, offset,
                            fileBytes.length - offset, StandardCharsets.UTF_8);
                    if (content.contains("\uFFFD")) {
                        content = new String(fileBytes, offset, fileBytes.length - offset,
                                java.nio.charset.Charset.forName("windows-1252"));
                    }
                    rawLines = splitCsvRows(content);
                }
            } catch (IOException ex) {
                try {
                    rawLines = Files.readAllLines(fc.getSelectedFile().toPath());
                } catch (IOException ex2) {
                    JOptionPane.showMessageDialog(this,
                            "Failed to read file:\n" + ex2.getMessage(),
                            "Error", JOptionPane.ERROR_MESSAGE);
                    return;
                }
            }
        } else {
            JTextArea pasteArea = new JTextArea(12, 50);
            pasteArea.setFont(new Font("Segoe UI", Font.PLAIN, 14));
            pasteArea.setLineWrap(false);
            JScrollPane sp = new JScrollPane(pasteArea);
            sp.setPreferredSize(new Dimension(600, 300));

            int result = JOptionPane.showConfirmDialog(this, sp,
                    "Paste CSV/TSV quiz settings (header row required):",
                    JOptionPane.OK_CANCEL_OPTION, JOptionPane.PLAIN_MESSAGE);
            if (result != JOptionPane.OK_OPTION) return;

            String text = pasteArea.getText();
            if (text.trim().isEmpty()) {
                JOptionPane.showMessageDialog(this, "No data entered.",
                        "Empty", JOptionPane.WARNING_MESSAGE);
                return;
            }
            rawLines = splitCsvRows(text);
        }

        // Trim trailing blank rows
        ArrayList<String> trimmed = new ArrayList<>(rawLines);
        while (!trimmed.isEmpty() && trimmed.get(trimmed.size() - 1).trim().isEmpty()) {
            trimmed.remove(trimmed.size() - 1);
        }

        if (trimmed.size() < 2) {
            JOptionPane.showMessageDialog(this,
                    "Need a header row plus at least one data row.\n"
                            + "First row must contain QUIZ_* column headers.",
                    "Quiz Import", JOptionPane.WARNING_MESSAGE);
            return;
        }

        List<String> headerFields = parseCsvLine(trimmed.get(0));
        Map<String, Integer> col = new HashMap<>();
        // textColByIndex: 1-based TEXTn -> CSV column index
        Map<Integer, Integer> textColByIndex = new TreeMap<>();
        int hlColIndex = -1;
        for (int i = 0; i < headerFields.size(); i++) {
            String h = headerFields.get(i).trim().toUpperCase(Locale.ROOT);
            // Accept both "QUIZ_X" and "QUIZ.X" header conventions.
            if (h.startsWith("QUIZ.")) h = "QUIZ_" + h.substring(5);
            if (h.startsWith("QUIZ_")) {
                col.put(h, i);
            } else if (h.equals("HL")) {
                hlColIndex = i;
            } else if (h.matches("TEXT\\d+")) {
                int n = Integer.parseInt(h.substring(4));
                if (n >= 1) textColByIndex.put(n, i);
            }
        }
        if (col.isEmpty() && textColByIndex.isEmpty() && hlColIndex < 0) {
            JOptionPane.showMessageDialog(this,
                    "No recognised columns in header row.\n"
                            + "Use TEXT1..TEXTn for slide texts, HL for highlight text,\n"
                            + "or QUIZ_* for quiz settings (e.g., QUIZ_ENABLED, QUIZ_CORRECT).",
                    "Quiz Import", JOptionPane.WARNING_MESSAGE);
            return;
        }

        List<SlideRow> targetSlides = new ArrayList<>();
        for (SlideRow row : slideRows) {
            if (!row.isTitleGridSlide) targetSlides.add(row);
        }

        int updated = 0;
        int audioBuilt = 0;
        List<String> warnings = new ArrayList<>();
        boolean visualsApplied = false;

        for (int r = 1; r < trimmed.size(); r++) {
            if (trimmed.get(r).trim().isEmpty()) continue;
            List<String> fields = parseCsvLine(trimmed.get(r));
            int slideIdx = r - 1;
            if (slideIdx >= targetSlides.size()) {
                warnings.add("Row " + (r + 1) + ": no matching slide (only "
                        + targetSlides.size() + " non-title-grid slides). Skipped.");
                continue;
            }
            SlideRow slide = targetSlides.get(slideIdx);
            QuizSlide q = slide.getQuiz();

            // Apply TEXT1..TEXTn columns -> slide text items (1-based -> 0-based).
            for (Map.Entry<Integer, Integer> e : textColByIndex.entrySet()) {
                int colIdx = e.getValue();
                if (colIdx < fields.size()) {
                    String cellText = fields.get(colIdx);
                    if (!cellText.isEmpty()) {
                        slide.setSlideTextAt(e.getKey() - 1, cellText);
                    }
                }
            }

            // Apply HL column -> slide-level + per-slide-text highlight.
            if (hlColIndex >= 0 && hlColIndex < fields.size()) {
                String hlText = fields.get(hlColIndex).trim();
                slide.setHighlightText(hlText);
                slide.setSlideTextHighlightText(hlText);
            }

            String s;
            s = quizCellAt(fields, col.get("QUIZ_ENABLED"));
            if (s != null && !s.trim().isEmpty()) q.enabled = parseQuizBool(s, q.enabled);

            s = quizCellAt(fields, col.get("QUIZ_CORRECT"));
            if (s != null && !s.trim().isEmpty()) {
                try {
                    int v = Integer.parseInt(s.trim());
                    if (v >= 1) q.correctOptionIndex = v;
                    else warnings.add("Row " + (r + 1) + ": QUIZ_CORRECT must be ≥ 1 (got '"
                            + s + "'). Ignored.");
                } catch (NumberFormatException nfe) {
                    warnings.add("Row " + (r + 1) + ": QUIZ_CORRECT not a number ('"
                            + s + "'). Ignored.");
                }
            }

            s = quizCellAt(fields, col.get("QUIZ_SECONDS"));
            if (s != null && !s.trim().isEmpty()) {
                try {
                    int v = Integer.parseInt(s.trim());
                    if (v >= 1) q.timerSeconds = v;
                    else warnings.add("Row " + (r + 1) + ": QUIZ_SECONDS must be ≥ 1 (got '"
                            + s + "'). Ignored.");
                } catch (NumberFormatException nfe) {
                    warnings.add("Row " + (r + 1) + ": QUIZ_SECONDS not a number ('"
                            + s + "'). Ignored.");
                }
            }

            s = quizCellAt(fields, col.get("QUIZ_RED_THRESHOLD"));
            if (s != null && !s.trim().isEmpty()) {
                try {
                    int v = Integer.parseInt(s.trim());
                    if (v >= 0) q.redThresholdSeconds = v;
                    else warnings.add("Row " + (r + 1)
                            + ": QUIZ_RED_THRESHOLD must be ≥ 0. Ignored.");
                } catch (NumberFormatException nfe) {
                    warnings.add("Row " + (r + 1)
                            + ": QUIZ_RED_THRESHOLD not a number. Ignored.");
                }
            }

            s = quizCellAt(fields, col.get("QUIZ_TICK"));
            if (s != null && !s.trim().isEmpty()) {
                applyQuizTickOrDing(s.trim(), importSourceDir, q, true, r + 1, warnings);
            }

            s = quizCellAt(fields, col.get("QUIZ_DING"));
            if (s != null && !s.trim().isEmpty()) {
                applyQuizTickOrDing(s.trim(), importSourceDir, q, false, r + 1, warnings);
            }

            s = quizCellAt(fields, col.get("QUIZ_QUESTION_AUDIO"));
            if (s != null && !s.trim().isEmpty()) {
                File af = resolveQuizPath(s.trim(), importSourceDir);
                if (af.exists()) {
                    q.questionAudioFile = af;
                    int dur = probeAudioDurationMs(af);
                    if (dur > 0) q.questionAudioDurationMs = dur;
                    else warnings.add("Row " + (r + 1)
                            + ": could not probe duration of '" + af.getName() + "'.");
                } else {
                    warnings.add("Row " + (r + 1)
                            + ": question audio not found: '" + s + "'.");
                }
            }

            // Shared visual fields read from FIRST data row only, then
            // broadcast to every slide further down.
            if (!visualsApplied) {
                applyQuizVisualFields(q, fields, col, r + 1, warnings);
                visualsApplied = true;
            }

            // If quiz is enabled and we have a question audio, build the
            // combined audio (question + tick × N + ding) and attach it as
            // the slide's audio — same path the Quiz dialog Save uses.
            if (q.enabled && q.questionAudioFile != null && q.questionAudioFile.exists()
                    && q.questionAudioDurationMs > 0) {
                try {
                    File built = QuizSlide.generateCombinedAudio(q);
                    int dur = probeAudioDurationMs(built);
                    q.generatedAudioFile = built;
                    q.generatedAudioDurationMs = dur;
                    q.questionEndMs = q.questionAudioDurationMs;
                    slide.setSlideAudio(0, built, dur);
                    audioBuilt++;
                } catch (Exception ex) {
                    warnings.add("Row " + (r + 1)
                            + ": failed to build quiz audio: " + ex.getMessage());
                }
            }

            slide.refreshQuizToolbarFromState();
            slide.schedulePreview();
            updated++;
        }

        // Broadcast first-row visuals to all non-title-grid slides (matches
        // preset behavior — see copyVisualSettingsFrom usage at line 591).
        if (visualsApplied && !targetSlides.isEmpty()) {
            QuizSlide srcQ = targetSlides.get(0).getQuiz();
            for (int i = 1; i < targetSlides.size(); i++) {
                targetSlides.get(i).getQuiz().copyVisualSettingsFrom(srcQ);
                targetSlides.get(i).refreshQuizToolbarFromState();
                targetSlides.get(i).schedulePreview();
            }
        }

        revalidate();
        repaint();

        StringBuilder msg = new StringBuilder();
        msg.append("Quiz Import complete.\n")
                .append("Slides updated: ").append(updated).append("\n")
                .append("Combined audio built: ").append(audioBuilt);
        if (!warnings.isEmpty()) {
            msg.append("\n\nWarnings (").append(warnings.size()).append("):");
            int show = Math.min(warnings.size(), 30);
            for (int i = 0; i < show; i++) {
                msg.append("\n  • ").append(warnings.get(i));
            }
            if (warnings.size() > show) {
                msg.append("\n  …and ").append(warnings.size() - show).append(" more.");
            }
        }
        JOptionPane.showMessageDialog(this, msg.toString(), "Quiz Import",
                warnings.isEmpty() ? JOptionPane.INFORMATION_MESSAGE
                        : JOptionPane.WARNING_MESSAGE);
    }

    private static String quizCellAt(List<String> fields, Integer idx) {
        if (idx == null) return null;
        if (idx < 0 || idx >= fields.size()) return "";
        return fields.get(idx);
    }

    private static boolean parseQuizBool(String s, boolean def) {
        if (s == null) return def;
        String v = s.trim().toLowerCase(Locale.ROOT);
        if (v.isEmpty()) return def;
        if (v.equals("true") || v.equals("1") || v.equals("yes")
                || v.equals("y") || v.equals("on")) return true;
        if (v.equals("false") || v.equals("0") || v.equals("no")
                || v.equals("n") || v.equals("off")) return false;
        return def;
    }

    private static File resolveQuizPath(String s, File base) {
        File f = new File(s);
        if (f.isAbsolute()) return f;
        if (base != null) return new File(base, s);
        return f;
    }

    private static void applyQuizTickOrDing(String cell, File base, QuizSlide q,
                                            boolean tick, int rowNum,
                                            List<String> warnings) {
        String[] valid = tick
                ? new String[] { "Stock: Classic Clock", "Stock: Game Show",
                "Stock: Soft Tap" }
                : new String[] { "Stock: Bell", "Stock: Chime", "Stock: Buzzer" };
        for (String name : valid) {
            if (name.equalsIgnoreCase(cell)) {
                if (tick) { q.tickPreset = name; q.customTickFile = null; }
                else      { q.dingPreset = name; q.customDingFile = null; }
                return;
            }
        }
        if (cell.equalsIgnoreCase("Custom")) {
            if (tick) q.tickPreset = "Custom";
            else      q.dingPreset = "Custom";
            return;
        }
        File f = resolveQuizPath(cell, base);
        if (f.exists()) {
            if (tick) { q.tickPreset = "Custom"; q.customTickFile = f; }
            else      { q.dingPreset = "Custom"; q.customDingFile = f; }
        } else {
            warnings.add("Row " + rowNum + ": "
                    + (tick ? "QUIZ_TICK" : "QUIZ_DING")
                    + " value '" + cell
                    + "' is not a known stock preset and not an existing file. Ignored.");
        }
    }

    private static void applyQuizVisualFields(QuizSlide q, List<String> fields,
                                              Map<String, Integer> col, int rowNum,
                                              List<String> warnings) {
        String s;
        s = quizCellAt(fields, col.get("QUIZ_TIMER_STYLE"));
        if (s != null && !s.trim().isEmpty()) q.timerStyle = s.trim();

        s = quizCellAt(fields, col.get("QUIZ_TIMER_X"));
        if (s != null && !s.trim().isEmpty())
            q.timerXPct = parseQuizPct(s, q.timerXPct, "QUIZ_TIMER_X", rowNum, warnings);

        s = quizCellAt(fields, col.get("QUIZ_TIMER_Y"));
        if (s != null && !s.trim().isEmpty())
            q.timerYPct = parseQuizPct(s, q.timerYPct, "QUIZ_TIMER_Y", rowNum, warnings);

        s = quizCellAt(fields, col.get("QUIZ_TIMER_SIZE"));
        if (s != null && !s.trim().isEmpty())
            q.timerSizePct = parseQuizPct(s, q.timerSizePct, "QUIZ_TIMER_SIZE", rowNum, warnings);

        s = quizCellAt(fields, col.get("QUIZ_TIMER_WIDTH"));
        if (s != null && !s.trim().isEmpty())
            q.timerWidthPct = parseQuizPct(s, q.timerWidthPct, "QUIZ_TIMER_WIDTH", rowNum, warnings);

        s = quizCellAt(fields, col.get("QUIZ_TIMER_COLOR"));
        if (s != null && !s.trim().isEmpty()) {
            Color c = parseQuizColor(s.trim());
            if (c != null) q.timerColor = c;
            else warnings.add("Row " + rowNum + ": QUIZ_TIMER_COLOR '"
                    + s + "' not recognised. Ignored.");
        }

        s = quizCellAt(fields, col.get("QUIZ_BAR_SHAPE"));
        if (s != null && !s.trim().isEmpty()) q.progressBarShape = s.trim();

        s = quizCellAt(fields, col.get("QUIZ_TIMER_TEXT_COLOR"));
        if (s != null && !s.trim().isEmpty()) {
            Color c = parseQuizColor(s.trim());
            if (c != null) q.timerTextColor = c;
            else warnings.add("Row " + rowNum + ": QUIZ_TIMER_TEXT_COLOR '"
                    + s + "' not recognised. Ignored.");
        }

        s = quizCellAt(fields, col.get("QUIZ_TIMER_FONT"));
        if (s != null && !s.trim().isEmpty()) q.timerFont = s.trim();

        s = quizCellAt(fields, col.get("QUIZ_TIMER_LABEL"));
        if (s != null) q.timerLabel = s;

        s = quizCellAt(fields, col.get("QUIZ_REVEAL_MARK_STYLE"));
        if (s != null && !s.trim().isEmpty()) q.revealMarkStyle = s.trim();

        s = quizCellAt(fields, col.get("QUIZ_REVEAL_MARK_SIZE"));
        if (s != null && !s.trim().isEmpty())
            q.revealMarkSizePct = parseQuizScalePct(s, q.revealMarkSizePct,
                    "QUIZ_REVEAL_MARK_SIZE", rowNum, warnings);

        s = quizCellAt(fields, col.get("QUIZ_REVEAL_MARK_COLOR"));
        if (s != null && !s.trim().isEmpty()) {
            Color c = parseQuizColor(s.trim());
            if (c != null) q.revealMarkColor = c;
            else warnings.add("Row " + rowNum + ": QUIZ_REVEAL_MARK_COLOR '"
                    + s + "' not recognised. Ignored.");
        }

        s = quizCellAt(fields, col.get("QUIZ_REVEAL_PAD"));
        if (s != null && !s.trim().isEmpty())
            q.revealPadPct = parseQuizScalePct0(s, q.revealPadPct,
                    "QUIZ_REVEAL_PAD", rowNum, warnings);

        s = quizCellAt(fields, col.get("QUIZ_TIMER_START_MODE"));
        if (s != null && !s.trim().isEmpty()) {
            String v = s.trim();
            if (v.equalsIgnoreCase("AtSlideStart")
                    || v.equalsIgnoreCase("at_slide_start")
                    || v.equalsIgnoreCase("start")) {
                q.timerStartMode = "AtSlideStart";
            } else if (v.equalsIgnoreCase("AfterQuestion")
                    || v.equalsIgnoreCase("after_question")
                    || v.equalsIgnoreCase("after")) {
                q.timerStartMode = "AfterQuestion";
            } else {
                warnings.add("Row " + rowNum + ": QUIZ_TIMER_START_MODE '"
                        + s + "' must be AtSlideStart or AfterQuestion. Ignored.");
            }
        }

        // Animation knobs + new custom colors.
        s = quizCellAt(fields, col.get("QUIZ_TIMER_ANIM"));
        if (s != null && !s.trim().isEmpty()) q.timerAnimation = s.trim();

        s = quizCellAt(fields, col.get("QUIZ_TIMER_ANIM_STRENGTH"));
        if (s != null && !s.trim().isEmpty())
            q.timerAnimStrengthPct = parseQuizScalePct0(s, q.timerAnimStrengthPct,
                    "QUIZ_TIMER_ANIM_STRENGTH", rowNum, warnings);

        s = quizCellAt(fields, col.get("QUIZ_TIMER_ANIM_TRIGGER"));
        if (s != null && !s.trim().isEmpty()) q.timerAnimTrigger = s.trim();

        s = quizCellAt(fields, col.get("QUIZ_TIMER_ANIM_EASING"));
        if (s != null && !s.trim().isEmpty()) q.timerAnimEasing = s.trim();

        s = quizCellAt(fields, col.get("QUIZ_TIMER_RED_COLOR"));
        if (s != null && !s.trim().isEmpty()) {
            Color c = parseQuizColor(s.trim());
            if (c != null) q.timerRedColor = c;
            else warnings.add("Row " + rowNum + ": QUIZ_TIMER_RED_COLOR '"
                    + s + "' not recognised. Ignored.");
        }
    }

    private static int parseQuizPct(String s, int def, String field, int rowNum,
                                    List<String> warnings) {
        try {
            int v = Integer.parseInt(s.trim());
            if (v < 0 || v > 100) {
                warnings.add("Row " + rowNum + ": " + field + "=" + v
                        + " out of 0..100. Ignored.");
                return def;
            }
            return v;
        } catch (NumberFormatException nfe) {
            warnings.add("Row " + rowNum + ": " + field + " not a number ('"
                    + s + "'). Ignored.");
            return def;
        }
    }

    /** Like parseQuizPct but bounded to 50..200 (used for the reveal size scaler). */
    private static int parseQuizScalePct(String s, int def, String field, int rowNum,
                                         List<String> warnings) {
        try {
            int v = Integer.parseInt(s.trim());
            if (v < 50 || v > 200) {
                warnings.add("Row " + rowNum + ": " + field + "=" + v
                        + " out of 50..200. Ignored.");
                return def;
            }
            return v;
        } catch (NumberFormatException nfe) {
            warnings.add("Row " + rowNum + ": " + field + " not a number ('"
                    + s + "'). Ignored.");
            return def;
        }
    }

    /** Like parseQuizScalePct but allows 0 (used for the reveal padding scaler). */
    private static int parseQuizScalePct0(String s, int def, String field, int rowNum,
                                          List<String> warnings) {
        try {
            int v = Integer.parseInt(s.trim());
            if (v < 0 || v > 200) {
                warnings.add("Row " + rowNum + ": " + field + "=" + v
                        + " out of 0..200. Ignored.");
                return def;
            }
            return v;
        } catch (NumberFormatException nfe) {
            warnings.add("Row " + rowNum + ": " + field + " not a number ('"
                    + s + "'). Ignored.");
            return def;
        }
    }

    private static Color parseQuizColor(String s) {
        if (s == null) return null;
        String v = s.trim();
        if (v.isEmpty()) return null;
        String hex = v.startsWith("#") ? v.substring(1) : v;
        if (hex.matches("[0-9A-Fa-f]{6}") || hex.matches("[0-9A-Fa-f]{8}")) {
            try {
                if (hex.length() == 6) return new Color(Integer.parseInt(hex, 16));
                int r = Integer.parseInt(hex.substring(0, 2), 16);
                int g = Integer.parseInt(hex.substring(2, 4), 16);
                int b = Integer.parseInt(hex.substring(4, 6), 16);
                int a = Integer.parseInt(hex.substring(6, 8), 16);
                return new Color(r, g, b, a);
            } catch (NumberFormatException ignored) {}
        }
        switch (v.toLowerCase(Locale.ROOT)) {
            case "white":   return Color.WHITE;
            case "black":   return Color.BLACK;
            case "red":     return Color.RED;
            case "green":   return Color.GREEN;
            case "blue":    return Color.BLUE;
            case "cyan":    return Color.CYAN;
            case "magenta": return Color.MAGENTA;
            case "yellow":  return Color.YELLOW;
            case "orange":  return Color.ORANGE;
            case "pink":    return Color.PINK;
            case "gray":
            case "grey":    return Color.GRAY;
            default:        return null;
        }
    }

    // ==================== Format Sync ====================

    void syncFormattingFromFirstSlide() {
        if (isSyncingFormat) return;
        if (slideRows.isEmpty()) return;

        SlideRow source = null;
        for (SlideRow row : slideRows) {
            if (!row.isTitleGridSlide) {
                source = row;
                break;
            }
        }
        if (source == null) return;

        String fontName = source.getSelectedFont();
        int fontSize = source.getFontSize();
        int fontStyle = source.getFontStyle();
        Color fontColor = source.getFontColor();
        int alignment = source.getTextAlignment();
        boolean showPin = source.isShowPin();
        String displayMode = source.getDisplayMode();
        int subtitleY = source.getSubtitleY();
        int subtitleBgOpacity = source.getSubtitleBgOpacity();
        boolean showSlideNumber = source.isShowSlideNumber();
        String slideNumberFontName = source.getSlideNumberFontName();
        int slideNumberX = source.getSlideNumberX();
        int slideNumberY = source.getSlideNumberY();
        int slideNumberSize = source.getSlideNumberSize();
        Color slideNumberColor = source.getSlideNumberColor();
        List<SlideTextData> slideTextFormats = source.getSlideTextFormats();
        List<SlidePictureData> slidePictureFormats = source.getSlidePictureFormats();
        boolean fxRoundCorners = source.isFxRoundCorners();
        int fxCornerRadius = source.getFxCornerRadius();
        boolean fxVignetteOn = source.fxVignetteCheck.isSelected();
        int fxVignetteVal = source.getFxVignetteRaw();
        boolean fxSepiaOn = source.fxSepiaCheck.isSelected();
        int fxSepiaVal = source.getFxSepiaRaw();
        boolean fxGrainOn = source.fxGrainCheck.isSelected();
        int fxGrainVal = source.getFxGrainRaw();
        boolean fxWaterRippleOn = source.fxWaterRippleCheck.isSelected();
        int fxWaterRippleVal = source.getFxWaterRippleRaw();
        boolean fxGlitchOn = source.fxGlitchCheck.isSelected();
        int fxGlitchVal = source.getFxGlitchRaw();
        boolean fxShakeOn = source.fxShakeCheck.isSelected();
        int fxShakeVal = source.getFxShakeRaw();
        boolean fxScanlineOn = source.fxScanlineCheck.isSelected();
        int fxScanlineVal = source.getFxScanlineRaw();
        boolean fxRaisedOn = source.fxRaisedCheck.isSelected();
        int fxRaisedVal = source.getFxRaisedRaw();
        String fxOtherKind = source.getFxOtherKind();
        int fxOtherVal = source.getFxOtherRaw();
        String overlayShape = source.getOverlayShape();
        String overlayBgMode = source.getOverlayBgMode();
        Color ovBgColor = source.getOverlayBgColor();
        int overlayX = source.getOverlayX();
        int overlayY = source.getOverlayY();
        int overlaySize = source.getOverlaySize();
        boolean textJustify = source.isTextJustify();
        int textWidthPct = source.getTextWidthPct();
        String highlightText = source.getHighlightText();
        Color hlColor = source.getHighlightColor();
        int textShiftX = source.getTextShiftX();
        File voFile = source.getSlideVideoOverlayFile();
        int voDurationMs = source.getSlideVideoOverlayDurationMs();
        int voX = source.getSlideVideoOverlayX();
        int voY = source.getSlideVideoOverlayY();
        int voSize = source.getSlideVideoOverlaySize();
        boolean voFill = source.isSlideVideoOverlayFill();
        boolean voBehind = source.isSlideVideoOverlayBehind();
        double audioGapSeconds = ((Number) source.audioGapSpinner.getValue()).doubleValue();
        // First slide is the master: broadcast its full per-text-row HL lists.
        List<Color>   audioHlColorList   = source.getAudioHlColorList();
        List<String>  audioHlEffectsList = source.getAudioHlEffectsList();
        List<Integer> audioGlowSizeList  = source.getAudioGlowSizeList();
        // Karaoke (toolbar 7d) per-row settings broadcast alongside audio HL —
        // word-timings themselves stay row-local since they're tied to that
        // row's audio file, but Word FX style + color follow the master.
        List<String>  karaokeStyleList   = source.getSlideAudioKaraokeStyleList();
        List<Color>   karaokeColorList   = source.getSlideAudioKaraokeColorList();

        isSyncingFormat = true;
        try {
            for (SlideRow row : slideRows) {
                if (row == source || row.isTitleGridSlide) continue;
                row.applyFormatting(fontName, fontSize, fontStyle, fontColor, alignment, showPin, displayMode, subtitleY, subtitleBgOpacity, source.getSourceVideoVolume(),
                        source.getBgTransparency(),
                        showSlideNumber, slideNumberFontName, slideNumberX, slideNumberY, slideNumberSize, slideNumberColor,
                        source.getSlideNumberStyle(), source.getSlideNumberEffect(),
                        slideTextFormats, slidePictureFormats,
                        fxRoundCorners, fxCornerRadius,
                        fxVignetteOn, fxVignetteVal, fxSepiaOn, fxSepiaVal,
                        fxGrainOn, fxGrainVal, fxWaterRippleOn, fxWaterRippleVal,
                        fxGlitchOn, fxGlitchVal, fxShakeOn, fxShakeVal,
                        fxScanlineOn, fxScanlineVal, fxRaisedOn, fxRaisedVal,
                        fxOtherKind, fxOtherVal,
                        overlayShape, overlayBgMode, ovBgColor, overlayX, overlayY, overlaySize,
                        textJustify, textWidthPct, highlightText, hlColor,
                        textShiftX,
                        voFile, voDurationMs, voX, voY, voSize, voFill, voBehind,
                        audioGapSeconds, audioHlColorList, audioHlEffectsList, audioGlowSizeList,
                        karaokeStyleList, karaokeColorList);
                // Broadcast the master row's quiz visual / shared settings
                // (everything except the per-slide enabled flag, correct
                // answer index, and question/generated audio files).
                row.getQuiz().copyVisualSettingsFrom(source.getQuiz());
                row.refreshQuizToolbarFromState();
            }
        } finally {
            isSyncingFormat = false;
        }
    }

    private void applyFirstSlideFormattingToAll() {
        if (slideRows.size() < 2) return;
        syncFormattingFromFirstSlide();
    }

    // ==================== Utility ====================

    private static int extractLeadingNumber(String name) {
        int dot = name.lastIndexOf('.');
        String base = dot > 0 ? name.substring(0, dot) : name;
        StringBuilder digits = new StringBuilder();
        for (char c : base.toCharArray()) {
            if (Character.isDigit(c)) digits.append(c);
            else if (digits.length() > 0) break;
        }
        if (digits.length() > 0) {
            try { return Integer.parseInt(digits.toString()); }
            catch (NumberFormatException e) { /* fall through */ }
        }
        return Integer.MAX_VALUE;
    }

    private JButton createStyledButton(String text, Color bg) {
        JButton btn = new JButton(text) {
            @Override
            protected void paintComponent(Graphics g) {
                Graphics2D g2 = (Graphics2D) g.create();
                g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
                g2.setColor(getModel().isPressed() ? bg.darker() : getModel().isRollover() ? bg.brighter() : bg);
                g2.fillRoundRect(0, 0, getWidth(), getHeight(), 12, 12);
                g2.setColor(Color.WHITE);
                g2.setFont(getFont());
                FontMetrics fm = g2.getFontMetrics();
                int x = (getWidth() - fm.stringWidth(getText())) / 2;
                int y = (getHeight() + fm.getAscent() - fm.getDescent()) / 2;
                g2.drawString(getText(), x, y);
                g2.dispose();
            }
        };
        btn.setFont(new Font("Segoe UI", Font.BOLD, 11));
        btn.setPreferredSize(new Dimension(110, 30));
        btn.setContentAreaFilled(false);
        btn.setBorderPainted(false);
        btn.setFocusPainted(false);
        btn.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
        return btn;
    }

    private void addSlideRow() {
        SlideRow row = new SlideRow(slideRows.size() + 1);
        slideRows.add(row);
        slidesPanel.add(row.getPanel());
        slidesPanel.add(Box.createRigidArea(new Dimension(0, 10)));

        if (slideRows.size() > 1) {
            applyFirstSlideFormattingToAll();
        }

        slidesPanel.revalidate();
        slidesPanel.repaint();
        SwingUtilities.invokeLater(() -> {
            JScrollBar vBar = scrollPane.getVerticalScrollBar();
            vBar.setValue(vBar.getMaximum());
        });
    }

    private void clearAllSlides() {
        if (slideRows.isEmpty()) return;
        int confirm = JOptionPane.showConfirmDialog(this,
                "Remove all " + slideRows.size() + " slides and start fresh?",
                "Clear All", JOptionPane.YES_NO_OPTION, JOptionPane.WARNING_MESSAGE);
        if (confirm != JOptionPane.YES_OPTION) return;
        slideRows.clear();
        slidesPanel.removeAll();
        slidesPanel.revalidate();
        slidesPanel.repaint();
        addSlideRow();
    }

    private void removeSlideRow(SlideRow row) {
        slideRows.remove(row);
        rebuildSlidesPanel();
    }

    private void moveSlideRow(SlideRow row, int direction) {
        int idx = slideRows.indexOf(row);
        int newIdx = idx + direction;
        if (newIdx < 0 || newIdx >= slideRows.size()) return;
        Collections.swap(slideRows, idx, newIdx);
        rebuildSlidesPanel();
        applyFirstSlideFormattingToAll();
    }

    private void rebuildSlidesPanel() {
        slidesPanel.removeAll();
        for (int i = 0; i < slideRows.size(); i++) {
            slideRows.get(i).updateNumber(i + 1);
            slidesPanel.add(slideRows.get(i).getPanel());
            slidesPanel.add(Box.createRigidArea(new Dimension(0, 10)));
        }
        slidesPanel.revalidate();
        slidesPanel.repaint();
    }

    // ==================== Image Loading ====================

    private static final String[] VIDEO_EXTS = {
            "mp4", "avi", "mov", "mkv", "webm", "flv", "wmv", "m4v", "mpg", "mpeg"
    };

    private static boolean isVideoFile(File file) {
        if (file == null) return false;
        String name = file.getName().toLowerCase();
        int dot = name.lastIndexOf('.');
        if (dot < 0) return false;
        String ext = name.substring(dot + 1);
        for (String v : VIDEO_EXTS) if (v.equals(ext)) return true;
        return false;
    }

    private static BufferedImage extractFirstVideoFrame(File videoFile) throws IOException {
        File tempPng = File.createTempFile("video_frame_", ".png");
        tempPng.deleteOnExit();
        try {
            ProcessBuilder pb = new ProcessBuilder(
                    "ffmpeg", "-y", "-i", videoFile.getAbsolutePath(),
                    "-vframes", "1", "-q:v", "2",
                    tempPng.getAbsolutePath());
            pb.redirectErrorStream(true);
            Process proc = pb.start();
            try (BufferedReader br = new BufferedReader(new InputStreamReader(proc.getInputStream()))) {
                while (br.readLine() != null) { /* drain */ }
            }
            int exitCode = proc.waitFor();
            if (exitCode != 0) {
                throw new IOException(
                        "ffmpeg failed to read first frame (exit " + exitCode + ").\n" +
                                "Ensure ffmpeg is installed: https://ffmpeg.org/download.html");
            }
            BufferedImage img = ImageIO.read(tempPng);
            if (img == null) throw new IOException("Failed to read extracted video frame.");
            return img;
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new IOException("Frame extraction interrupted.", e);
        } finally {
            tempPng.delete();
        }
    }

    private static BufferedImage loadImageFile(File file) throws IOException {
        String name = file.getName().toLowerCase();
        if (name.endsWith(".avif") || name.endsWith(".heif") || name.endsWith(".heic")) {
            return loadWithFfmpeg(file);
        }
        BufferedImage img = ImageIO.read(file);
        if (img == null) {
            return loadWithFfmpeg(file);
        }
        return img;
    }

    private static BufferedImage loadWithFfmpeg(File file) throws IOException {
        File tempPng = File.createTempFile("img_convert_", ".png");
        tempPng.deleteOnExit();
        try {
            ProcessBuilder pb = new ProcessBuilder(
                    "ffmpeg", "-y", "-i", file.getAbsolutePath(), tempPng.getAbsolutePath());
            pb.redirectErrorStream(true);
            Process proc = pb.start();
            try (BufferedReader br = new BufferedReader(new InputStreamReader(proc.getInputStream()))) {
                while (br.readLine() != null) { /* drain */ }
            }
            int exitCode = proc.waitFor();
            if (exitCode != 0) {
                throw new IOException(
                        "ffmpeg failed (exit " + exitCode + ").\n" +
                                "Ensure ffmpeg is installed: https://ffmpeg.org/download.html");
            }
            BufferedImage img = ImageIO.read(tempPng);
            if (img == null) throw new IOException("Failed to read converted image.");
            return img;
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new IOException("Conversion interrupted.", e);
        } finally {
            tempPng.delete();
        }
    }

