                            bulkMarginSpinner.setValue(0);
                            bulkWidthSpinner.setValue(100);
                            bulkCornerSpinner.setValue(0);
                            bulkBorderSpinner.setValue(0);
                            bulkFitCombo.setSelectedItem("Fill");
