        // ===== Slide picture dropdown helpers =====

        private void saveCurrentSlidePictureToItem() {
            if (currentSlidePictureIndex < 0 || currentSlidePictureIndex >= slidePictureItems.size()) return;
            slidePictureItems.set(currentSlidePictureIndex, new SlidePictureData(
                    slidePicShowCheck.isSelected(), slidePicLoadedImage, slidePicLoadedFile,
                    (int) slidePicXSpinner.getValue(), (int) slidePicYSpinner.getValue(),
                    (int) slidePicWidthSpinner.getValue(),
                    (String) slidePicShapeCombo.getSelectedItem(),
                    (int) slidePicCornerSpinner.getValue()));
        }

        private void loadSlidePictureFromItem(int index) {
            if (index < 0 || index >= slidePictureItems.size()) return;
            isLoadingSlidePicture = true;
            try {
                SlidePictureData item = slidePictureItems.get(index);
                slidePicShowCheck.setSelected(item.show);
                slidePicLoadedImage = item.image;
                slidePicLoadedFile = item.imageFile;
                slidePicXSpinner.setValue(item.x);
                slidePicYSpinner.setValue(item.y);
                slidePicWidthSpinner.setValue(item.widthPct);
                slidePicShapeCombo.setSelectedItem(item.shape);
                slidePicCornerSpinner.setValue(item.cornerRadius);
                updateSlidePicPreview();
            } finally {
                isLoadingSlidePicture = false;
            }
        }

        private void rebuildSlidePicSelector() {
            slidePicSelector.removeAllItems();
            for (int i = 0; i < slidePictureItems.size(); i++) {
                slidePicSelector.addItem("Pic " + (i + 1));
            }
        }

        private void updateSlidePicPreview() {
            if (slidePicLoadedImage != null) {
                int pw = slidePicPreviewLabel.getPreferredSize().width;
                int ph = slidePicPreviewLabel.getPreferredSize().height;
                double sc = Math.min((double) pw / slidePicLoadedImage.getWidth(),
                        (double) ph / slidePicLoadedImage.getHeight());
                Image scaled = slidePicLoadedImage.getScaledInstance(
                        Math.max(1, (int) (slidePicLoadedImage.getWidth() * sc)),
                        Math.max(1, (int) (slidePicLoadedImage.getHeight() * sc)),
                        Image.SCALE_SMOOTH);
                slidePicPreviewLabel.setIcon(new ImageIcon(scaled));
                slidePicPreviewLabel.setText(null);
            } else {
                slidePicPreviewLabel.setIcon(null);
                slidePicPreviewLabel.setText("No image");
            }
        }

        private void updateBulkCountLabel() {
            bulkCountLabel.setText(bulkGridItems.size() + (bulkGridItems.size() == 1 ? " image" : " images"));
        }

        private void clearBulkItemUI() {
            isLoadingBulkItem = true;
            try {
                bulkItemLoadedImage = null;
                bulkItemLoadedFile = null;
                bulkItemAudioFile = null;
                bulkItemAudioDurationMs = -1;
                bulkItemPreviewLabel.setIcon(null);
                bulkItemPreviewLabel.setText("No image");
                bulkAudioLabel.setText("No audio");
                bulkEffectCombo.setSelectedIndex(0);
                bulkItemSizeSpinner.setValue(100);
                bulkItemXSpinner.setValue(-1);
                bulkItemYSpinner.setValue(-1);
            } finally {
                isLoadingBulkItem = false;
            }
        }

        private void saveBulkItemToList() {
            if (currentBulkIndex < 0 || currentBulkIndex >= bulkGridItems.size()) return;
            SlidePictureData old = bulkGridItems.get(currentBulkIndex);
            int perItemSize = (int) bulkItemSizeSpinner.getValue();
            int manualX = (int) bulkItemXSpinner.getValue(); // -1 = auto
            int manualY = (int) bulkItemYSpinner.getValue(); // -1 = auto
            bulkGridItems.set(currentBulkIndex, new SlidePictureData(
                    true, bulkItemLoadedImage, bulkItemLoadedFile,
                    manualX, manualY, perItemSize, old.shape, old.cornerRadius,
                    bulkItemAudioFile, bulkItemAudioDurationMs,
                    (String) bulkEffectCombo.getSelectedItem()));
        }

        private void loadBulkItemFromList(int index) {
            if (index < 0 || index >= bulkGridItems.size()) return;
            isLoadingBulkItem = true;
            try {
                SlidePictureData item = bulkGridItems.get(index);
                bulkItemLoadedImage = item.image;
                bulkItemLoadedFile = item.imageFile;
                bulkItemAudioFile = item.audioFile;
                bulkItemAudioDurationMs = item.audioDurationMs;
                int storedSize = item.widthPct > 0 ? item.widthPct : 100;
                bulkItemSizeSpinner.setValue(Math.min(200, Math.max(10, storedSize)));
                bulkItemXSpinner.setValue(Math.max(-1, Math.min(100, item.x)));
                bulkItemYSpinner.setValue(Math.max(-1, Math.min(100, item.y)));
                updateBulkItemPreview();
                bulkAudioLabel.setText(item.audioFile != null ? item.audioFile.getName() : "No audio");
                String fx = item.audioEffect != null ? item.audioEffect : "None";
                bulkEffectCombo.setSelectedItem(fx);
            } finally {
                isLoadingBulkItem = false;
            }
        }

        private void rebuildBulkItemSelector() {
            bulkItemSelector.removeAllItems();
            if (bulkGridItems.isEmpty()) {
                bulkItemSelector.addItem("(none)");
            } else {
                for (int i = 0; i < bulkGridItems.size(); i++) {
                    bulkItemSelector.addItem("Img " + (i + 1));
                }
            }
        }

        private void updateBulkItemPreview() {
            if (bulkItemLoadedImage != null) {
                int pw = bulkItemPreviewLabel.getPreferredSize().width;
                int ph = bulkItemPreviewLabel.getPreferredSize().height;
                double sc = Math.min((double) pw / bulkItemLoadedImage.getWidth(),
                        (double) ph / bulkItemLoadedImage.getHeight());
                Image scaled = bulkItemLoadedImage.getScaledInstance(
                        Math.max(1, (int) (bulkItemLoadedImage.getWidth() * sc)),
                        Math.max(1, (int) (bulkItemLoadedImage.getHeight() * sc)),
                        Image.SCALE_SMOOTH);
                bulkItemPreviewLabel.setIcon(new ImageIcon(scaled));
                bulkItemPreviewLabel.setText(null);
            } else {
                bulkItemPreviewLabel.setIcon(null);
                bulkItemPreviewLabel.setText("No image");
            }
        }

        private static double[][] getCollageCells(String name) {
            // Each cell: [left%, top%, right%, bottom%] in 0-100 coordinate space
            if (name == null) return null;
            switch (name) {
                // ── 2-image ──────────────────────────────────
                case "Side by Side (2)":
                    return new double[][]{{0,0,50,100},{50,0,100,100}};
                case "Stacked (2)":
                    return new double[][]{{0,0,100,50},{0,50,100,100}};
                case "Feature + Side (2)":
                    return new double[][]{{0,0,65,100},{65,0,100,100}};
                // ── 3-image ──────────────────────────────────
                case "Hero Left (3)":
                    return new double[][]{{0,0,60,100},{60,0,100,50},{60,50,100,100}};
                case "Hero Right (3)":
                    return new double[][]{{0,0,40,50},{0,50,40,100},{40,0,100,100}};
                case "Hero Top (3)":
                    return new double[][]{{0,0,100,60},{0,60,50,100},{50,60,100,100}};
                case "Triptych (3)":
                    return new double[][]{{0,0,33.4,100},{33.3,0,66.7,100},{66.6,0,100,100}};
                // ── 4-image ──────────────────────────────────
                case "Big Left + 3 (4)":
                    return new double[][]{{0,0,60,100},{60,0,100,33.4},{60,33.3,100,66.7},{60,66.6,100,100}};
                case "3 + Big Right (4)":
                    return new double[][]{{0,0,40,33.4},{0,33.3,40,66.7},{0,66.6,40,100},{40,0,100,100}};
                case "Big Top + 3 (4)":
                    return new double[][]{{0,0,100,60},{0,60,33.4,100},{33.3,60,66.7,100},{66.6,60,100,100}};
                case "2×2 Equal (4)":
                    return new double[][]{{0,0,50,50},{50,0,100,50},{0,50,50,100},{50,50,100,100}};
                // ── 5-image ──────────────────────────────────
                case "Magazine (5)":
                    return new double[][]{{0,0,55,65},{55,0,100,33},{55,33,100,65},{0,65,35,100},{35,65,100,100}};
                case "2 + 3 Strips (5)":
                    return new double[][]{{0,0,50,50},{50,0,100,50},{0,50,33.4,100},{33.3,50,66.7,100},{66.6,50,100,100}};
                // ── 6-image ──────────────────────────────────
                case "Feature Mosaic (6)":
                    return new double[][]{{0,0,25,40},{25,0,50,40},{50,0,100,60},{0,40,50,65},{0,65,30,100},{30,65,100,100}};
                default:
                    return null;
            }
        }

        private List<SlidePictureData> computeBulkGridPositions() {
            List<SlidePictureData> out = new ArrayList<>();
            if (bulkGridItems.isEmpty()) return out;

            int slideW = getOutputWidth();
            int slideH = getOutputHeight();
            int shorter = Math.min(slideW, slideH);
            int gapPct    = (int) bulkGapSpinner.getValue();
            int marginPct = (int) bulkMarginSpinner.getValue();
            int sizeScalePct = (int) bulkWidthSpinner.getValue();

            int gapPx    = shorter * gapPct    / 100;  // can be negative (overlap)
            int marginPx = shorter * marginPct / 100;  // always >= 0

            int cornerRadius = (int) bulkCornerSpinner.getValue();
            int borderWidth  = (int) bulkBorderSpinner.getValue();
            Color borderColor = bulkBorderColor;
            int opacity = (int) bulkOpacitySpinner.getValue();
            String fitMode = (String) bulkFitCombo.getSelectedItem();
            if (fitMode == null) fitMode = "Fit";

            // Audio slot base index
            int textAudioCount = 0;
            {
                int maxIdx = -1;
                for (int k : slideAudioFiles.keySet()) if (k > maxIdx) maxIdx = k;
                textAudioCount = maxIdx + 1;
            }
            int bulkAudioSlot = textAudioCount;

            // ── Collage mode ─────────────────────────────────────────────────────────
            String collageName = (String) bulkCollageCombo.getSelectedItem();
            double[][] collageCells = (collageName != null && !collageName.startsWith("—"))
                    ? getCollageCells(collageName) : null;

            if (collageCells != null) {
                int usableW = slideW - 2 * marginPx;
                int usableH = slideH - 2 * marginPx;
                int n = Math.min(bulkGridItems.size(), collageCells.length);
                for (int i = 0; i < n; i++) {
                    SlidePictureData src = bulkGridItems.get(i);
                    double[] cell = collageCells[i];
                    // Map cell [0-100] to pixel rect within the usable (margin-inset) area
                    int leftPx   = marginPx + (int) Math.round(usableW * cell[0] / 100.0);
                    int topPx    = marginPx + (int) Math.round(usableH * cell[1] / 100.0);
                    int rightPx  = marginPx + (int) Math.round(usableW * cell[2] / 100.0);
                    int bottomPx = marginPx + (int) Math.round(usableH * cell[3] / 100.0);
                    // Apply uniform half-gap inset on all 4 sides
                    int halfGap = gapPx / 2;
                    int imgLeft   = leftPx   + halfGap;
                    int imgTop    = topPx    + halfGap;
                    int imgRight  = rightPx  - (gapPx - halfGap);
                    int imgBottom = bottomPx - (gapPx - halfGap);
                    int cellW = Math.max(1, imgRight  - imgLeft);
                    int cellH = Math.max(1, imgBottom - imgTop);
                    int cellCX = imgLeft + cellW / 2;
                    int cellCY = imgTop  + cellH / 2;
                    // Apply global size% and per-item size%
                    int perItemScale = src.widthPct > 0 ? src.widthPct : 100;
                    int finalW = Math.max(1, cellW * sizeScalePct / 100 * perItemScale / 100);
                    int finalH = Math.max(1, cellH * sizeScalePct / 100 * perItemScale / 100);
                    int cx   = src.x >= 0 ? src.x : (int) Math.round(cellCX * 100.0 / slideW);
                    int cy   = src.y >= 0 ? src.y : (int) Math.round(cellCY * 100.0 / slideH);
                    int wPct = (int) Math.round(finalW  * 100.0 / slideW);
                    int hPct = (int) Math.round(finalH  * 100.0 / slideH);
                    int audioActiveIdx = -1;
                    if (src.audioFile != null && src.audioFile.exists() && src.audioDurationMs > 0) {
                        audioActiveIdx = bulkAudioSlot++;
                    }
                    out.add(new SlidePictureData(true, src.image, src.imageFile, cx, cy, Math.max(1, wPct),
                            src.shape, cornerRadius, src.audioFile, src.audioDurationMs,
                            src.audioEffect, Math.max(1, hPct), audioActiveIdx,
                            borderWidth, borderColor, opacity, fitMode));
                }
                return out;
            }

            // ── Grid mode (original logic) ────────────────────────────────────────────
            String layout = (String) bulkLayoutCombo.getSelectedItem();
            int n = bulkGridItems.size();
            int cols, rows;
            if (layout == null || layout.startsWith("1×N")) {
                cols = 1; rows = n;
            } else if (layout.equals("2×1")) { cols = 2; rows = 1;
            } else if (layout.equals("3×1")) { cols = 3; rows = 1;
            } else if (layout.equals("4×1")) { cols = 4; rows = 1;
            } else if (layout.equals("2×2")) { cols = 2; rows = 2;
            } else if (layout.equals("3×2")) { cols = 3; rows = 2;
            } else if (layout.equals("4×2")) { cols = 4; rows = 2;
            } else if (layout.equals("1×2")) { cols = 1; rows = 2;
            } else if (layout.equals("1×3")) { cols = 1; rows = 3;
            } else { cols = (int) Math.ceil(Math.sqrt(n)); rows = (int) Math.ceil((double) n / cols); }

            int usableW = slideW - 2 * marginPx;
            int usableH = slideH - 2 * marginPx;
            int startX  = marginPx;
            int startY  = marginPx;
            int colWidthPx  = Math.max(1, (usableW - (cols - 1) * gapPx) / cols);
            int rowHeightPx = Math.max(1, (usableH - (rows - 1) * gapPx) / rows);
            int imgBoxW = Math.max(1, colWidthPx  * sizeScalePct / 100);
            int imgBoxH = Math.max(1, rowHeightPx * sizeScalePct / 100);

            for (int i = 0; i < n; i++) {
                SlidePictureData src = bulkGridItems.get(i);
                int c = i % cols;
                int r = i / cols;
                if (r >= rows) break;
                int cellCenterX = startX + c * (colWidthPx + gapPx) + colWidthPx / 2;
                int cellCenterY = startY + r * (rowHeightPx + gapPx) + rowHeightPx / 2;
                int perItemScale = src.widthPct > 0 ? src.widthPct : 100;
                int itemBoxW = Math.max(1, imgBoxW * perItemScale / 100);
                int itemBoxH = Math.max(1, imgBoxH * perItemScale / 100);
                int cx   = src.x >= 0 ? src.x : (int) Math.round(cellCenterX * 100.0 / slideW);
                int cy   = src.y >= 0 ? src.y : (int) Math.round(cellCenterY * 100.0 / slideH);
                int wPct = (int) Math.round(itemBoxW * 100.0 / slideW);
                int hPct = (int) Math.round(itemBoxH * 100.0 / slideH);
                int audioActiveIdx = -1;
                if (src.audioFile != null && src.audioFile.exists() && src.audioDurationMs > 0) {
                    audioActiveIdx = bulkAudioSlot++;
                }
                out.add(new SlidePictureData(true, src.image, src.imageFile, cx, cy, Math.max(1, wPct),
                        src.shape, cornerRadius, src.audioFile, src.audioDurationMs,
                        src.audioEffect, Math.max(1, hPct), audioActiveIdx,
                        borderWidth, borderColor, opacity, fitMode));
            }
            return out;
        }

        List<SlidePictureData> getSlidePictureDataList() {
            saveCurrentSlidePictureToItem();
            List<SlidePictureData> result = new ArrayList<>(slidePictureItems);
            if (bulkGridShowCheck != null && bulkGridShowCheck.isSelected() && !bulkGridItems.isEmpty()) {
                result.addAll(computeBulkGridPositions());
            }
            return result;
        }

        List<SlidePictureData> getSlidePictureFormats() {
            return getSlidePictureDataList();
        }

        void applySlidePictureFormats(List<SlidePictureData> formats) {
            if (formats == null || formats.isEmpty()) return;
            // Ensure we have at least as many items as the source.
            while (slidePictureItems.size() < formats.size()) {
                slidePictureItems.add(new SlidePictureData(false, null, null, 50, 50, 20, "Rectangle", 0));
            }
            // Sync position/size/shape from master, preserve each slide's own image and show state.
            for (int i = 0; i < formats.size(); i++) {
                SlidePictureData fmt = formats.get(i);
                SlidePictureData existing = slidePictureItems.get(i);
                boolean show = existing.image != null ? existing.show : fmt.show;
                slidePictureItems.set(i, new SlidePictureData(show,
                        existing.image, existing.imageFile,
                        fmt.x, fmt.y, fmt.widthPct, fmt.shape, fmt.cornerRadius));
            }
            if (currentSlidePictureIndex >= slidePictureItems.size()) {
                currentSlidePictureIndex = 0;
            }
            isLoadingSlidePicture = true;
            try {
                rebuildSlidePicSelector();
                slidePicSelector.setSelectedIndex(currentSlidePictureIndex);
            } finally {
                isLoadingSlidePicture = false;
            }
            loadSlidePictureFromItem(currentSlidePictureIndex);
            schedulePreview();
        }

        private void onFormatChanged() {
            schedulePreview();
            updateTextAreaStyle();
            if (!isSyncingFormat && !isTitleGridSlide && !slideRows.isEmpty()) {
                for (SlideRow row : slideRows) {
                    if (!row.isTitleGridSlide) {
                        if (row == this) {
                            syncFormattingFromFirstSlide();
                        }
                        break;
                    }
                }
            }
        }

