        private void browseImage() {
            JFileChooser fc = new JFileChooser();
            fc.setFileFilter(new FileNameExtensionFilter(
                    "Images & Videos (jpg, png, gif, bmp, webp, avif, heif, mp4, mov, webm, mkv, avi, wmv, flv, m4v, mpg)",
                    "jpg", "jpeg", "png", "gif", "bmp", "webp", "avif", "heif", "heic",
                    "mp4", "avi", "mov", "mkv", "webm", "flv", "wmv", "m4v", "mpg", "mpeg"));
            if (fc.showOpenDialog(panel) == JFileChooser.APPROVE_OPTION)
                loadImage(fc.getSelectedFile());
        }


        private void loadImage(File file) {
            if (isVideoFile(file)) {
                loadVideoAsSlide(file);
                return;
            }
            try {
                BufferedImage img = loadImageFile(file);
                if (img == null) {
                    JOptionPane.showMessageDialog(panel, "Cannot read: " + file.getName(),
                            "Error", JOptionPane.ERROR_MESSAGE);
                    return;
                }
                if (isTitleGridSlide) {
                    titleBgImage = img;
                    updateImagePreviewThumb("BG: " + file.getName());
                } else {
                    loadedImage = img;
                    // Replacing with an image clears any prior video-slide source.
                    sourceVideoFile = null;
                    sourceVideoDurationMs = -1;
                    updateImagePreviewThumb(file.getName());
                }
                schedulePreview();
            } catch (IOException ex) {
                JOptionPane.showMessageDialog(panel, "Error:\n" + ex.getMessage(),
                        "Error", JOptionPane.ERROR_MESSAGE);
            }
        }

        private void loadVideoAsSlide(File videoFile) {
            if (isTitleGridSlide) {
                JOptionPane.showMessageDialog(panel,
                        "Title grid slides accept only images, not video.",
                        "Video Upload", JOptionPane.WARNING_MESSAGE);
                return;
            }
            int durationMs = probeAudioDurationMs(videoFile);
            if (durationMs <= 0) {
                JOptionPane.showMessageDialog(panel,
                        "Could not read video duration.\nMake sure ffprobe is installed.",
                        "Video Error", JOptionPane.ERROR_MESSAGE);
                return;
            }
            BufferedImage firstFrame;
            try {
                firstFrame = extractFirstVideoFrame(videoFile);
            } catch (IOException ex) {
                JOptionPane.showMessageDialog(panel,
                        "Could not extract first frame:\n" + ex.getMessage(),
                        "Video Error", JOptionPane.ERROR_MESSAGE);
                return;
            }
            loadedImage = firstFrame;
            sourceVideoFile = videoFile;
            sourceVideoDurationMs = durationMs;
            updateImagePreviewThumb("\uD83C\uDFAC " + videoFile.getName());
            schedulePreview();
        }

        void setImageDirectly(BufferedImage img, String fileName) {
            this.loadedImage = img;
            this.sourceVideoFile = null;
            this.sourceVideoDurationMs = -1;
            updateImagePreviewThumb(fileName);
            schedulePreview();
        }

        void setVideoSlideDirectly(File videoFile, BufferedImage firstFrame, int durationMs) {
            this.loadedImage = firstFrame;
            this.sourceVideoFile = videoFile;
            this.sourceVideoDurationMs = durationMs;
            updateImagePreviewThumb("\uD83C\uDFAC " + videoFile.getName());
            schedulePreview();
        }

        File getSourceVideoFile() { return sourceVideoFile; }
        int getSourceVideoDurationMs() { return sourceVideoDurationMs; }
        int getSourceVideoVolume() { return (int) sourceVideoVolumeSpinner.getValue(); }
        int getBgTransparency() { return (int) bgTransparencySpinner.getValue(); }

        private void updateImagePreviewThumb(String fileName) {
            BufferedImage thumbSource = (isTitleGridSlide && titleBgImage != null) ? titleBgImage : loadedImage;
            if (thumbSource == null) return;
            int pw = imagePreview.getWidth() - 16;
            int ph = imagePreview.getHeight() - 16;
            if (pw < 50) pw = 240;
            if (ph < 50) ph = 130;
            double sc = Math.min((double) pw / thumbSource.getWidth(), (double) ph / thumbSource.getHeight());
            Image thumb = thumbSource.getScaledInstance(
                    Math.max(1, (int) (thumbSource.getWidth() * sc)),
                    Math.max(1, (int) (thumbSource.getHeight() * sc)),
                    Image.SCALE_SMOOTH);
            imagePreview.setIcon(new ImageIcon(thumb));
            imagePreview.setText(fileName);
        }

